{
  "name": "Babu Video Studio AI",
  "description": "Professional AI Video Generator optimized for Bengali creators. Create 9:16 and 16:9 videos from text.",
  "requestFramePermissions": []
}

import { GoogleGenAI, Modality } from "@google/genai";

export interface Scene {
  image: string;
  text: string;
  audio: Uint8Array;
}

export class GeminiService {
  private static decode(base64: string) {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  }

  static async generateScript(prompt: string, lang: string, ratio: string): Promise<any[]> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const systemInstruction = `You are a professional video content creator. 
    Create a 3-scene video storyboard in ${lang} based on the prompt: "${prompt}".
    For each scene:
    1. Provide a "text" (max 15 words) for narration and subtitles in ${lang}.
    2. Provide an "img_prompt" in English. This prompt must be highly descriptive, cinematic, and optimized for a ${ratio} aspect ratio.
    Output MUST be valid JSON: { "scenes": [{ "img_prompt": "string", "text": "string" }] }`;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          systemInstruction,
          responseMimeType: "application/json",
          temperature: 0.7
        }
      });

      const data = JSON.parse(response.text || '{}');
      return data.scenes || [];
    } catch (e: any) {
      console.error("Script generation failed:", e);
      throw e;
    }
  }

  static async generateImage(prompt: string, ratio: string): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const response = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: `Cinematic masterpiece, hyper-realistic, 8k, professional lighting, depth of field, ${prompt}`,
        config: {
          numberOfImages: 1,
          outputMimeType: 'image/jpeg',
          aspectRatio: ratio === '16:9' ? '16:9' : '9:16',
        },
      });

      const base64Image = response.generatedImages[0].image.imageBytes;
      return `data:image/jpeg;base64,${base64Image}`;
    } catch (e: any) {
      console.warn("Imagen 4.0 failed, falling back to Pro Image...");
      const fallback = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: { parts: [{ text: `Cinematic photography, high detail: ${prompt}` }] },
        config: {
          imageConfig: { 
            aspectRatio: ratio === '16:9' ? '16:9' : '9:16',
            imageSize: "1K"
          }
        }
      });
      const part = fallback.candidates?.[0]?.content?.parts.find(p => p.inlineData);
      return `data:image/png;base64,${part?.inlineData?.data}`;
    }
  }

  static async generateAudio(text: string, voiceName: string): Promise<Uint8Array> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName },
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (!base64Audio) throw new Error("Audio generation failed");
      return GeminiService.decode(base64Audio);
    } catch (e: any) {
      console.error("Audio generation failed:", e);
      throw e;
    }
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { 
  Play, Video, Download, Loader2, RefreshCw, Smartphone, Monitor, ShieldCheck, Zap,
  Sparkles, Layers, Volume2, Settings2, ArrowRight, CheckCircle2
} from 'lucide-react';
import { GeminiService } from './services/geminiService';

const LANGUAGES = [
  { id: 'bn', name: 'Bengali (বাংলা)', voice: 'Kore' },
  { id: 'en', name: 'English', voice: 'Puck' },
];

const RATIOS = [
  { id: '9:16', name: 'Portrait (Reel)', width: 720, height: 1280, icon: <Smartphone size={14} /> },
  { id: '16:9', name: 'Landscape', width: 1280, height: 720, icon: <Monitor size={14} /> }
];

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [slides, setSlides] = useState<any[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [status, setStatus] = useState('');
  const [exporting, setExporting] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [ratio, setRatio] = useState(RATIOS[0]);
  const [lang, setLang] = useState(LANGUAGES[0]);
  const [isKeySelected, setIsKeySelected] = useState<boolean | null>(null);

  const audioRef = useRef(new Audio());

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeySelected(hasKey);
      } else {
        setIsKeySelected(true);
      }
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
      setIsKeySelected(true);
    }
  };

  const pcmToWav = (pcmData: Int16Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + pcmData.length * 2);
    const view = new DataView(buffer);
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i));
    };
    writeString(0, 'RIFF');
    view.setUint32(4, 32 + pcmData.length * 2, true);
    writeString(8, 'WAVE');
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(36, 'data');
    view.setUint32(40, pcmData.length * 2, true);
    for (let i = 0; i < pcmData.length; i++) view.setInt16(44 + i * 2, pcmData[i], true);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const generate = async () => {
    if (!prompt.trim()) {
        setStatus("দয়া করে ভিডিওর বিষয়টি লিখুন!");
        return;
    }
    setLoading(true);
    setStatus('স্ক্রিপ্ট তৈরি হচ্ছে...');
    setSlides([]);
    setCurrentIndex(0);

    try {
      const scenes = await GeminiService.generateScript(prompt, lang.name, ratio.id);

      const newSlides: any[] = [];
      for (let i = 0; i < scenes.length; i++) {
        setStatus(`দৃশ্য ${i + 1}/3 এর ছবি তৈরি হচ্ছে...`);
        const imgUrl = await GeminiService.generateImage(scenes[i].img_prompt, ratio.id);

        setStatus(`দৃশ্য ${i + 1}/3 এর অডিও তৈরি হচ্ছে...`);
        const audioBytes = await GeminiService.generateAudio(scenes[i].text, lang.voice);

        const wavBlob = pcmToWav(new Int16Array(audioBytes.buffer), 24000);
        const audioUrl = URL.createObjectURL(wavBlob);

        newSlides.push({ image: imgUrl, text: scenes[i].text, audio: audioUrl });
        setSlides([...newSlides]);
      }
      setStatus('আপনার ভিডিও এখন প্রস্তুত!');
    } catch (e: any) {
      console.error(e);
      if (e.message?.includes("Requested entity was not found")) {
        setStatus("API Key এর সমস্যা, আবার ট্রাই করুন।");
        setIsKeySelected(false);
      } else {
        setStatus('কিছু একটা ভুল হয়েছে। ইন্টারন্টে কানেকশন চেক করুন।');
      }
    } finally {
      setLoading(false);
    }
  };

  const play = async () => {
    if (isPlaying || slides.length === 0) return;
    setIsPlaying(true);
    for (let i = 0; i < slides.length; i++) {
      setCurrentIndex(i);
      audioRef.current.src = slides[i].audio;
      await audioRef.current.play();
      await new Promise(r => audioRef.current.onended = r);
    }
    setIsPlaying(false);
    setCurrentIndex(0);
  };

  const download = async () => {
    if (slides.length === 0) return;
    setExporting(true);
    setStatus("ভিডিও ফাইল রেন্ডার হচ্ছে...");

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    canvas.width = ratio.width;
    canvas.height = ratio.height;

    const stream = canvas.captureStream(30);
    const mediaRecorder = new MediaRecorder(stream, { 
      mimeType: 'video/webm;codecs=vp9', 
      videoBitsPerSecond: 8000000 
    });
    const chunks: Blob[] = [];
    mediaRecorder.ondataavailable = (e) => chunks.push(e.data);
    mediaRecorder.onstop = () => {
      const blob = new Blob(chunks, { type: 'video/webm' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Babu_Video_${Date.now()}.webm`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      setExporting(false);
      setStatus("ডাউনলোড সম্পন্ন হয়েছে!");
    };

    mediaRecorder.start();

    for (const slide of slides) {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = slide.image;
      await new Promise<void>(res => {
        img.onload = async () => {
          // Play for roughly 4 seconds per scene
          for (let f = 0; f < 120; f++) {
            ctx.fillStyle = '#000';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            const s = Math.max(canvas.width / img.width, canvas.height / img.height);
            const w = img.width * s, h = img.height * s;
            ctx.drawImage(img, (canvas.width - w) / 2, (canvas.height - h) / 2, w, h);

            // Subtitles
            const fontSize = Math.floor(canvas.width * 0.045);
            ctx.font = `bold ${fontSize}px 'Inter', sans-serif`;
            ctx.textAlign = 'center';

            const words = slide.text.split(' ');
            let lines: string[] = [], line = '';
            for (let word of words) {
              if (ctx.measureText(line + word).width > canvas.width * 0.8) {
                lines.push(line.trim());
                line = word + ' ';
              } else { line += word + ' '; }
            }
            lines.push(line.trim());

            const boxH = lines.length * fontSize * 1.5 + 40;
            ctx.fillStyle = 'rgba(0,0,0,0.6)';
            ctx.fillRect(0, canvas.height - boxH - 60, canvas.width, boxH);

            ctx.fillStyle = '#FFF';
            lines.forEach((l, idx) => {
              ctx.fillText(l, canvas.width / 2, (canvas.height - boxH - 10) + (idx * fontSize * 1.4));
            });

            await new Promise(rq => requestAnimationFrame(rq));
          }
          res();
        };
      });
    }
    mediaRecorder.stop();
  };

  if (isKeySelected === false) {
    return (
      <div className="min-h-screen bg-[#050505] text-white flex flex-col items-center justify-center p-8 text-center">
        <div className="max-w-md w-full space-y-8 p-10 bg-zinc-900/50 rounded-[3rem] border border-white/5 backdrop-blur-3xl shadow-2xl">
          <div className="flex justify-center">
            <div className="bg-yellow-500/10 p-6 rounded-full ring-1 ring-yellow-500/20">
              <ShieldCheck size={64} className="text-yellow-500" />
            </div>
          </div>
          <div className="space-y-4">
            <h2 className="text-4xl font-black tracking-tight">STUDIO ACCESS</h2>
            <p className="text-zinc-400 text-sm leading-relaxed">
              আপনার পেইড এপিআই কি ব্যবহার করে হাই-কোয়ালিটি ভিডিও তৈরি করতে প্রসেসটি চালু করুন।
            </p>
          </div>
          <button 
            onClick={handleSelectKey}
            className="w-full bg-yellow-500 text-black font-black py-6 rounded-2xl flex items-center justify-center gap-3 hover:bg-yellow-400 transition-all active:scale-95 shadow-xl shadow-yellow-500/20"
          >
            <Zap size={20} fill="currentColor" />
            LAUNCH STUDIO
          </button>
          <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="block text-[10px] text-zinc-500 uppercase tracking-widest font-bold hover:text-yellow-500 transition-colors">Billing Documentation</a>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#050505] text-white selection:bg-yellow-500 selection:text-black">
      <div className="max-w-6xl mx-auto flex flex-col lg:flex-row h-screen">

        {/* Sidebar / Form */}
        <aside className="w-full lg:w-96 p-6 lg:p-10 border-r border-white/5 flex flex-col gap-8 bg-zinc-900/20 backdrop-blur-xl">
          <div className="flex items-center gap-3">
            <div className="bg-yellow-500 p-2.5 rounded-2xl text-black shadow-lg shadow-yellow-500/20">
              <Sparkles size={24} fill="currentColor"/>
            </div>
            <div>
              <h1 className="text-xl font-black tracking-tighter uppercase leading-none">Babu Studio</h1>
              <p className="text-[10px] font-bold text-yellow-500 uppercase tracking-widest mt-1">AI Video Engine</p>
            </div>
          </div>

          <div className="flex-1 space-y-8 overflow-y-auto pr-2 custom-scrollbar">
            <section className="space-y-4">
              <div className="flex items-center gap-2 text-zinc-500">
                <Layers size={14} />
                <span className="text-[10px] font-black uppercase tracking-widest">Script Writing</span>
              </div>
              <textarea 
                className="w-full bg-zinc-900/50 rounded-3xl p-6 text-sm border border-white/5 focus:border-yellow-500/30 focus:ring-4 focus:ring-yellow-500/5 outline-none resize-none placeholder:text-zinc-700 text-zinc-200 transition-all min-h-[120px]"
                placeholder="ভিডিওর জন্য প্রম্পট লিখুন... (যেমন: একটি রহস্যময় বনের গল্প)"
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
              />
            </section>

            <section className="space-y-4">
              <div className="flex items-center gap-2 text-zinc-500">
                <Settings2 size={14} />
                <span className="text-[10px] font-black uppercase tracking-widest">Configuration</span>
              </div>

              <div className="grid grid-cols-2 gap-3">
                {RATIOS.map(r => (
                  <button 
                    key={r.id}
                    onClick={() => setRatio(r)}
                    className={`flex flex-col items-center gap-2 p-4 rounded-3xl border transition-all ${ratio.id === r.id ? 'bg-white text-black border-white shadow-xl' : 'bg-zinc-900/50 text-zinc-500 border-white/5 hover:bg-zinc-800'}`}
                  >
                    {r.icon}
                    <span className="text-[10px] font-bold uppercase">{r.name}</span>
                  </button>
                ))}
              </div>

              <div className="space-y-3">
                <div className="relative">
                  <select 
                    className="w-full bg-zinc-900/50 p-5 rounded-2xl border border-white/5 text-[11px] font-black uppercase tracking-widest outline-none cursor-pointer text-zinc-400 appearance-none hover:bg-zinc-800 transition-colors" 
                    value={lang.id} 
                    onChange={(e) => setLang(LANGUAGES.find(l => l.id === e.target.value)!)}
                  >
                    {LANGUAGES.map(l => <option key={l.id} value={l.id}>{l.name}</option>)}
                  </select>
                  <div className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none text-zinc-600">
                    <ArrowRight size={14} />
                  </div>
                </div>
              </div>
            </section>
          </div>

          <button 
            onClick={generate} 
            disabled={loading} 
            className="w-full bg-yellow-500 text-black font-black rounded-2xl py-6 flex items-center justify-center gap-3 hover:bg-yellow-400 active:scale-95 transition-all disabled:opacity-50 shadow-2xl shadow-yellow-500/20"
          >
            {loading ? <Loader2 className="animate-spin" size={20}/> : <RefreshCw size={20} strokeWidth={3}/>}
            {loading ? "PROCESSING..." : "GENERATE VIDEO"}
          </button>
        </aside>

        {/* Main Preview Area */}
        <main className="flex-1 p-6 lg:p-10 flex flex-col items-center justify-center relative bg-[radial-gradient(circle_at_center,_#111_0%,_#050505_100%)]">
          <div 
            className="relative w-full max-w-2xl bg-zinc-900 rounded-[3rem] overflow-hidden border border-white/5 shadow-[0_0_100px_rgba(0,0,0,0.5)] flex flex-col items-center justify-center group"
            style={{ 
              aspectRatio: ratio.id === '9:16' ? '9/16' : '16/9', 
              maxHeight: '80vh' 
            }}
          >
            {slides.length > 0 ? (
              <>
                <img src={slides[currentIndex].image} className="w-full h-full object-cover transition-opacity duration-700 ease-in-out" alt="preview" />
                <div className="absolute inset-x-0 bottom-0 p-12 bg-gradient-to-t from-black via-black/80 to-transparent">
                  <p className="text-center font-bold text-2xl lg:text-3xl text-white drop-shadow-2xl leading-tight animate-in fade-in slide-in-from-bottom-4 duration-500">{slides[currentIndex].text}</p>
                </div>

                {!isPlaying && (
                  <button onClick={play} className="absolute inset-0 flex items-center justify-center bg-black/40 group-hover:bg-black/20 transition-all backdrop-blur-[2px]">
                    <div className="bg-white text-black p-8 rounded-full shadow-2xl scale-100 hover:scale-110 active:scale-90 transition-all duration-300">
                      <Play fill="currentColor" size={48} />
                    </div>
                  </button>
                )}
              </>
            ) : (
              <div className="text-zinc-800 flex flex-col items-center gap-6">
                <div className="bg-zinc-900 p-12 rounded-full border border-white/5 shadow-inner">
                  <Video size={64} className="opacity-10" />
                </div>
                <div className="text-center space-y-2">
                  <p className="text-[12px] font-black uppercase tracking-[0.6em] opacity-30">Studio Preview</p>
                  <p className="text-[10px] font-medium text-zinc-600 uppercase tracking-widest">Create a reel to see magic</p>
                </div>
              </div>
            )}

            {loading && (
              <div className="absolute inset-0 bg-black/90 backdrop-blur-2xl flex flex-col items-center justify-center gap-10 z-50">
                <div className="relative">
                  <div className="w-24 h-24 rounded-full border-t-4 border-yellow-500 animate-spin" />
                  <div className="absolute inset-0 flex items-center justify-center">
                    <Sparkles className="text-yellow-500 animate-pulse" size={32} />
                  </div>
                </div>
                <div className="text-center space-y-3">
                  <p className="text-[10px] text-zinc-500 font-black uppercase tracking-[0.4em] animate-pulse">Babu Engine Active</p>
                  <p className="text-xl font-bold text-white px-10 max-w-xs">{status}</p>
                </div>
              </div>
            )}
          </div>

          {/* Action Footer */}
          {slides.length > 0 && !loading && (
            <div className="mt-8 flex gap-4 animate-in fade-in zoom-in duration-700">
              <button 
                onClick={download} 
                disabled={exporting} 
                className="bg-white text-black px-10 py-5 rounded-2xl font-black flex items-center gap-3 hover:bg-zinc-200 transition-all active:scale-95 shadow-2xl"
              >
                {exporting ? <Loader2 className="animate-spin" size={22} /> : <Download size={22} strokeWidth={3} />}
                {exporting ? "EXPORTING..." : "DOWNLOAD REEL"}
              </button>
              <button 
                onClick={() => setSlides([])} 
                className="bg-zinc-900 border border-white/5 text-zinc-500 px-6 py-5 rounded-2xl font-black hover:text-white transition-all"
              >
                <RefreshCw size={22} />
              </button>
            </div>
          )}

          {status && !loading && slides.length > 0 && (
            <div className="absolute bottom-10 flex items-center gap-2 bg-green-500/10 text-green-500 px-4 py-2 rounded-full border border-green-500/20">
              <CheckCircle2 size={14} />
              <span className="text-[10px] font-black uppercase tracking-widest">{status}</span>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { 
  Play, Video, Download, Loader2, RefreshCw, Smartphone, Monitor, ShieldCheck, Zap,
  Sparkles, Layers, Settings2, ArrowRight, CheckCircle2, ChevronRight, Wand2
} from 'lucide-react';
import { GeminiService } from './services/geminiService';

const LANGUAGES = [
  { id: 'bn', name: 'Bengali (বাংলা)', voice: 'Kore' },
  { id: 'en', name: 'English', voice: 'Puck' },
];

const RATIOS = [
  { id: '9:16', name: 'Portrait (Reel)', width: 720, height: 1280, icon: <Smartphone size={14} /> },
  { id: '16:9', name: 'Landscape', width: 1280, height: 720, icon: <Monitor size={14} /> }
];

const App: React.FC = () => {
  const [isLaunched, setIsLaunched] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [slides, setSlides] = useState<any[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [status, setStatus] = useState('');
  const [exporting, setExporting] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [ratio, setRatio] = useState(RATIOS[0]);
  const [lang, setLang] = useState(LANGUAGES[0]);
  const [isKeySelected, setIsKeySelected] = useState<boolean | null>(null);

  const audioRef = useRef(new Audio());

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeySelected(hasKey);
      } else {
        setIsKeySelected(true);
      }
    };
    checkKey();
  }, []);

  const handleLaunch = async () => {
    if (!isKeySelected) {
      if (window.aistudio?.openSelectKey) {
        await window.aistudio.openSelectKey();
        setIsKeySelected(true);
      }
    }
    setIsLaunched(true);
  };

  const pcmToWav = (pcmData: Int16Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + pcmData.length * 2);
    const view = new DataView(buffer);
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i));
    };
    writeString(0, 'RIFF');
    view.setUint32(4, 32 + pcmData.length * 2, true);
    writeString(8, 'WAVE');
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(36, 'data');
    view.setUint32(40, pcmData.length * 2, true);
    for (let i = 0; i < pcmData.length; i++) view.setInt16(44 + i * 2, pcmData[i], true);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const generate = async () => {
    if (!prompt.trim()) {
        setStatus("দয়া করে ভিডিওর বিষয়টি লিখুন!");
        return;
    }
    setLoading(true);
    setStatus('স্ক্রিপ্ট তৈরি হচ্ছে...');
    setSlides([]);
    setCurrentIndex(0);

    try {
      const scenes = await GeminiService.generateScript(prompt, lang.name, ratio.id);

      const newSlides: any[] = [];
      for (let i = 0; i < scenes.length; i++) {
        setStatus(`দৃশ্য ${i + 1}/3 এর ছবি তৈরি হচ্ছে...`);
        const imgUrl = await GeminiService.generateImage(scenes[i].img_prompt, ratio.id);

        setStatus(`দৃশ্য ${i + 1}/3 এর অডিও তৈরি হচ্ছে...`);
        const audioBytes = await GeminiService.generateAudio(scenes[i].text, lang.voice);

        const wavBlob = pcmToWav(new Int16Array(audioBytes.buffer), 24000);
        const audioUrl = URL.createObjectURL(wavBlob);

        newSlides.push({ image: imgUrl, text: scenes[i].text, audio: audioUrl });
        setSlides([...newSlides]);
      }
      setStatus('আপনার ভিডিও এখন প্রস্তুত!');
    } catch (e: any) {
      console.error(e);
      if (e.message?.includes("Requested entity was not found")) {
        setStatus("API Key এর সমস্যা, আবার ট্রাই করুন।");
        setIsKeySelected(false);
        setIsLaunched(false);
      } else {
        setStatus('কিছু একটা ভুল হয়েছে। ইন্টারন্টে কানেকশন চেক করুন।');
      }
    } finally {
      setLoading(false);
    }
  };

  const play = async () => {
    if (isPlaying || slides.length === 0) return;
    setIsPlaying(true);
    for (let i = 0; i < slides.length; i++) {
      setCurrentIndex(i);
      audioRef.current.src = slides[i].audio;
      await audioRef.current.play();
      await new Promise(r => audioRef.current.onended = r);
    }
    setIsPlaying(false);
    setCurrentIndex(0);
  };

  const download = async () => {
    if (slides.length === 0) return;
    setExporting(true);
    setStatus("ভিডিও ফাইল রেন্ডার হচ্ছে...");

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    canvas.width = ratio.width;
    canvas.height = ratio.height;

    const stream = canvas.captureStream(30);
    const mediaRecorder = new MediaRecorder(stream, { 
      mimeType: 'video/webm;codecs=vp9', 
      videoBitsPerSecond: 8000000 
    });
    const chunks: Blob[] = [];
    mediaRecorder.ondataavailable = (e) => chunks.push(e.data);
    mediaRecorder.onstop = () => {
      const blob = new Blob(chunks, { type: 'video/webm' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Babu_Video_${Date.now()}.webm`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      setExporting(false);
      setStatus("ডাউনলোড সম্পন্ন হয়েছে!");
    };

    mediaRecorder.start();

    for (const slide of slides) {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = slide.image;
      await new Promise<void>(res => {
        img.onload = async () => {
          for (let f = 0; f < 120; f++) {
            ctx.fillStyle = '#000';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            const s = Math.max(canvas.width / img.width, canvas.height / img.height);
            const w = img.width * s, h = img.height * s;
            ctx.drawImage(img, (canvas.width - w) / 2, (canvas.height - h) / 2, w, h);

            const fontSize = Math.floor(canvas.width * 0.045);
            ctx.font = `bold ${fontSize}px 'Inter', sans-serif`;
            ctx.textAlign = 'center';

            const words = slide.text.split(' ');
            let lines: string[] = [], line = '';
            for (let word of words) {
              if (ctx.measureText(line + word).width > canvas.width * 0.8) {
                lines.push(line.trim());
                line = word + ' ';
              } else { line += word + ' '; }
            }
            lines.push(line.trim());

            const boxH = lines.length * fontSize * 1.5 + 40;
            ctx.fillStyle = 'rgba(0,0,0,0.6)';
            ctx.fillRect(0, canvas.height - boxH - 60, canvas.width, boxH);

            ctx.fillStyle = '#FFF';
            lines.forEach((l, idx) => {
              ctx.fillText(l, canvas.width / 2, (canvas.height - boxH - 10) + (idx * fontSize * 1.4));
            });

            await new Promise(rq => requestAnimationFrame(rq));
          }
          res();
        };
      });
    }
    mediaRecorder.stop();
  };

  // Launch / Landing Screen
  if (!isLaunched) {
    return (
      <div className="min-h-screen bg-[#050505] text-white flex flex-col items-center justify-center relative overflow-hidden">
        {/* Animated Background Orbs */}
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-yellow-500/10 rounded-full blur-[120px] animate-pulse" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-yellow-500/5 rounded-full blur-[120px]" />

        <div className="max-w-4xl w-full px-8 flex flex-col items-center text-center z-10 space-y-12 animate-in fade-in slide-in-from-bottom-10 duration-1000">
          <div className="space-y-6">
            <div className="inline-flex items-center gap-2 bg-zinc-900/50 border border-white/5 px-6 py-2 rounded-full mb-4">
              <Sparkles size={16} className="text-yellow-500" />
              <span className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-400">Powered by Gemini 3.0</span>
            </div>

            <h1 className="text-6xl md:text-8xl font-black tracking-tighter leading-[0.9]">
              BABU <span className="text-yellow-500">STUDIO</span>
            </h1>

            <p className="text-zinc-400 text-lg md:text-xl max-w-xl mx-auto font-medium leading-relaxed">
              আপনার কল্পনাকে মুহূর্তেই হাই-কোয়ালিটি বাংলা ভিডিওতে রূপান্তর করুন।
            </p>
          </div>

          <div className="flex flex-col sm:flex-row gap-4 w-full max-w-md">
            <button 
              onClick={handleLaunch}
              className="group relative flex-1 bg-yellow-500 text-black font-black py-6 rounded-2xl flex items-center justify-center gap-3 overflow-hidden shadow-[0_0_40px_rgba(250,204,21,0.2)] hover:shadow-[0_0_60px_rgba(250,204,21,0.4)] transition-all active:scale-95"
            >
              <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-500" />
              <span className="relative z-10 flex items-center gap-2">
                <Wand2 size={20} fill="currentColor" />
                LAUNCH STUDIO
              </span>
              <ChevronRight size={18} className="relative z-10 group-hover:translate-x-1 transition-transform" />
            </button>
          </div>

          {!isKeySelected && isKeySelected !== null && (
             <div className="bg-zinc-900/50 border border-white/5 p-6 rounded-3xl max-w-sm flex items-start gap-4 text-left">
                <ShieldCheck className="text-yellow-500 shrink-0 mt-1" size={24} />
                <div className="space-y-1">
                  <p className="text-xs font-bold text-white uppercase tracking-wider">API Key Required</p>
                  <p className="text-[10px] text-zinc-500 leading-normal">
                    ভিডিও তৈরির জন্য আপনার পেইড এপিআই কি প্রয়োজন। লঞ্চ বাটনে ক্লিক করে কি সেটআপ করুন।
                  </p>
                </div>
             </div>
          )}

          <div className="pt-20 grid grid-cols-2 md:grid-cols-3 gap-8 opacity-40 grayscale hover:grayscale-0 transition-all duration-700">
             <div className="flex flex-col items-center gap-2">
               <Video size={24} />
               <span className="text-[10px] font-black uppercase tracking-widest">Cinematic AI</span>
             </div>
             <div className="flex flex-col items-center gap-2">
               <Smartphone size={24} />
               <span className="text-[10px] font-black uppercase tracking-widest">Reels & Shorts</span>
             </div>
             <div className="hidden md:flex flex-col items-center gap-2">
               <Settings2 size={24} />
               <span className="text-[10px] font-black uppercase tracking-widest">Multi-Lang</span>
             </div>
          </div>
        </div>

        {/* Floating Background Text */}
        <div className="absolute bottom-10 left-10 pointer-events-none select-none opacity-[0.02]">
           <h2 className="text-[200px] font-black leading-none">AI VIDEO</h2>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#050505] text-white selection:bg-yellow-500 selection:text-black">
      <div className="max-w-6xl mx-auto flex flex-col lg:flex-row h-screen">

        {/* Sidebar / Form */}
        <aside className="w-full lg:w-96 p-6 lg:p-10 border-r border-white/5 flex flex-col gap-8 bg-zinc-900/20 backdrop-blur-xl">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3 cursor-pointer" onClick={() => setIsLaunched(false)}>
              <div className="bg-yellow-500 p-2.5 rounded-2xl text-black shadow-lg shadow-yellow-500/20">
                <Sparkles size={24} fill="currentColor"/>
              </div>
              <div>
                <h1 className="text-xl font-black tracking-tighter uppercase leading-none">Babu Studio</h1>
                <p className="text-[10px] font-bold text-yellow-500 uppercase tracking-widest mt-1">AI Video Engine</p>
              </div>
            </div>
          </div>

          <div className="flex-1 space-y-8 overflow-y-auto pr-2 custom-scrollbar">
            <section className="space-y-4">
              <div className="flex items-center gap-2 text-zinc-500">
                <Layers size={14} />
                <span className="text-[10px] font-black uppercase tracking-widest">Script Writing</span>
              </div>
              <textarea 
                className="w-full bg-zinc-900/50 rounded-3xl p-6 text-sm border border-white/5 focus:border-yellow-500/30 focus:ring-4 focus:ring-yellow-500/5 outline-none resize-none placeholder:text-zinc-700 text-zinc-200 transition-all min-h-[120px]"
                placeholder="ভিডিওর জন্য প্রম্পট লিখুন... (যেমন: একটি রহস্যময় বনের গল্প)"
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
              />
            </section>

            <section className="space-y-4">
              <div className="flex items-center gap-2 text-zinc-500">
                <Settings2 size={14} />
                <span className="text-[10px] font-black uppercase tracking-widest">Configuration</span>
              </div>

              <div className="grid grid-cols-2 gap-3">
                {RATIOS.map(r => (
                  <button 
                    key={r.id}
                    onClick={() => setRatio(r)}
                    className={`flex flex-col items-center gap-2 p-4 rounded-3xl border transition-all ${ratio.id === r.id ? 'bg-white text-black border-white shadow-xl' : 'bg-zinc-900/50 text-zinc-500 border-white/5 hover:bg-zinc-800'}`}
                  >
                    {r.icon}
                    <span className="text-[10px] font-bold uppercase">{r.name}</span>
                  </button>
                ))}
              </div>

              <div className="space-y-3">
                <div className="relative">
                  <select 
                    className="w-full bg-zinc-900/50 p-5 rounded-2xl border border-white/5 text-[11px] font-black uppercase tracking-widest outline-none cursor-pointer text-zinc-400 appearance-none hover:bg-zinc-800 transition-colors" 
                    value={lang.id} 
                    onChange={(e) => setLang(LANGUAGES.find(l => l.id === e.target.value)!)}
                  >
                    {LANGUAGES.map(l => <option key={l.id} value={l.id}>{l.name}</option>)}
                  </select>
                  <div className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none text-zinc-600">
                    <ArrowRight size={14} />
                  </div>
                </div>
              </div>
            </section>
          </div>

          <button 
            onClick={generate} 
            disabled={loading} 
            className="w-full bg-yellow-500 text-black font-black rounded-2xl py-6 flex items-center justify-center gap-3 hover:bg-yellow-400 active:scale-95 transition-all disabled:opacity-50 shadow-2xl shadow-yellow-500/20"
          >
            {loading ? <Loader2 className="animate-spin" size={20}/> : <RefreshCw size={20} strokeWidth={3}/>}
            {loading ? "PROCESSING..." : "GENERATE VIDEO"}
          </button>
        </aside>

        {/* Main Preview Area */}
        <main className="flex-1 p-6 lg:p-10 flex flex-col items-center justify-center relative bg-[radial-gradient(circle_at_center,_#111_0%,_#050505_100%)]">
          <div 
            className="relative w-full max-w-2xl bg-zinc-900 rounded-[3rem] overflow-hidden border border-white/5 shadow-[0_0_100px_rgba(0,0,0,0.5)] flex flex-col items-center justify-center group"
            style={{ 
              aspectRatio: ratio.id === '9:16' ? '9/16' : '16/9', 
              maxHeight: '80vh' 
            }}
          >
            {slides.length > 0 ? (
              <>
                <img src={slides[currentIndex].image} className="w-full h-full object-cover transition-opacity duration-700 ease-in-out" alt="preview" />
                <div className="absolute inset-x-0 bottom-0 p-12 bg-gradient-to-t from-black via-black/80 to-transparent">
                  <p className="text-center font-bold text-2xl lg:text-3xl text-white drop-shadow-2xl leading-tight animate-in fade-in slide-in-from-bottom-4 duration-500">{slides[currentIndex].text}</p>
                </div>

                {!isPlaying && (
                  <button onClick={play} className="absolute inset-0 flex items-center justify-center bg-black/40 group-hover:bg-black/20 transition-all backdrop-blur-[2px]">
                    <div className="bg-white text-black p-8 rounded-full shadow-2xl scale-100 hover:scale-110 active:scale-90 transition-all duration-300">
                      <Play fill="currentColor" size={48} />
                    </div>
                  </button>
                )}
              </>
            ) : (
              <div className="text-zinc-800 flex flex-col items-center gap-6">
                <div className="bg-zinc-900 p-12 rounded-full border border-white/5 shadow-inner">
                  <Video size={64} className="opacity-10" />
                </div>
                <div className="text-center space-y-2">
                  <p className="text-[12px] font-black uppercase tracking-[0.6em] opacity-30">Studio Preview</p>
                  <p className="text-[10px] font-medium text-zinc-600 uppercase tracking-widest">Create a reel to see magic</p>
                </div>
              </div>
            )}

            {loading && (
              <div className="absolute inset-0 bg-black/90 backdrop-blur-2xl flex flex-col items-center justify-center gap-10 z-50">
                <div className="relative">
                  <div className="w-24 h-24 rounded-full border-t-4 border-yellow-500 animate-spin" />
                  <div className="absolute inset-0 flex items-center justify-center">
                    <Sparkles className="text-yellow-500 animate-pulse" size={32} />
                  </div>
                </div>
                <div className="text-center space-y-3">
                  <p className="text-[10px] text-zinc-500 font-black uppercase tracking-[0.4em] animate-pulse">Babu Engine Active</p>
                  <p className="text-xl font-bold text-white px-10 max-w-xs">{status}</p>
                </div>
              </div>
            )}
          </div>

          {slides.length > 0 && !loading && (
            <div className="mt-8 flex gap-4 animate-in fade-in zoom-in duration-700">
              <button 
                onClick={download} 
                disabled={exporting} 
                className="bg-white text-black px-10 py-5 rounded-2xl font-black flex items-center gap-3 hover:bg-zinc-200 transition-all active:scale-95 shadow-2xl"
              >
                {exporting ? <Loader2 className="animate-spin" size={22} /> : <Download size={22} strokeWidth={3} />}
                {exporting ? "EXPORTING..." : "DOWNLOAD REEL"}
              </button>
              <button 
                onClick={() => setSlides([])} 
                className="bg-zinc-900 border border-white/5 text-zinc-500 px-6 py-5 rounded-2xl font-black hover:text-white transition-all"
              >
                <RefreshCw size={22} />
              </button>
            </div>
          )}

          {status && !loading && slides.length > 0 && (
            <div className="absolute bottom-10 flex items-center gap-2 bg-green-500/10 text-green-500 px-4 py-2 rounded-full border border-green-500/20">
              <CheckCircle2 size={14} />
              <span className="text-[10px] font-black uppercase tracking-widest">{status}</span>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { 
  Play, Video, Download, Loader2, RefreshCw, Smartphone, Monitor, ShieldCheck, Zap,
  Sparkles, Layers, Settings2, ArrowRight, CheckCircle2, ChevronRight, Wand2
} from 'lucide-react';
import { GeminiService } from './services/geminiService';

const LANGUAGES = [
  { id: 'bn', name: 'Bengali (বাংলা)', voice: 'Kore' },
  { id: 'en', name: 'English', voice: 'Puck' },
];

const RATIOS = [
  { id: '9:16', name: 'Portrait (Reel)', width: 720, height: 1280, icon: <Smartphone size={14} /> },
  { id: '16:9', name: 'Landscape', width: 1280, height: 720, icon: <Monitor size={14} /> }
];

const App: React.FC = () => {
  const [isLaunched, setIsLaunched] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [slides, setSlides] = useState<any[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [status, setStatus] = useState('');
  const [exporting, setExporting] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [ratio, setRatio] = useState(RATIOS[0]);
  const [lang, setLang] = useState(LANGUAGES[0]);
  const [isKeySelected, setIsKeySelected] = useState<boolean | null>(null);

  const audioRef = useRef(new Audio());

  useEffect(() => {
    const checkKey = async () => {
      // Check if the AI Studio API key environment is ready
      if (window.aistudio?.hasSelectedApiKey) {
        try {
          const hasKey = await window.aistudio.hasSelectedApiKey();
          setIsKeySelected(hasKey);
        } catch (e) {
          console.error("Error checking API key", e);
          setIsKeySelected(false);
        }
      } else {
        // Fallback for non-AI Studio environments
        setIsKeySelected(true);
      }
    };
    checkKey();
  }, []);

  const handleLaunch = async () => {
    if (isKeySelected === false) {
      if (window.aistudio?.openSelectKey) {
        await window.aistudio.openSelectKey();
        setIsKeySelected(true); // Assume success after opening dialog
      }
    }
    setIsLaunched(true);
  };

  const pcmToWav = (pcmData: Int16Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + pcmData.length * 2);
    const view = new DataView(buffer);
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i));
    };
    writeString(0, 'RIFF');
    view.setUint32(4, 32 + pcmData.length * 2, true);
    writeString(8, 'WAVE');
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(36, 'data');
    view.setUint32(40, pcmData.length * 2, true);
    for (let i = 0; i < pcmData.length; i++) view.setInt16(44 + i * 2, pcmData[i], true);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const generate = async () => {
    if (!prompt.trim()) {
        setStatus("দয়া করে ভিডিওর বিষয়টি লিখুন!");
        return;
    }
    setLoading(true);
    setStatus('স্ক্রিপ্ট তৈরি হচ্ছে...');
    setSlides([]);
    setCurrentIndex(0);

    try {
      const scenes = await GeminiService.generateScript(prompt, lang.name, ratio.id);

      const newSlides: any[] = [];
      for (let i = 0; i < scenes.length; i++) {
        setStatus(`দৃশ্য ${i + 1}/3 এর ছবি তৈরি হচ্ছে...`);
        const imgUrl = await GeminiService.generateImage(scenes[i].img_prompt, ratio.id);

        setStatus(`দৃশ্য ${i + 1}/3 এর অডিও তৈরি হচ্ছে...`);
        const audioBytes = await GeminiService.generateAudio(scenes[i].text, lang.voice);

        const wavBlob = pcmToWav(new Int16Array(audioBytes.buffer), 24000);
        const audioUrl = URL.createObjectURL(wavBlob);

        newSlides.push({ image: imgUrl, text: scenes[i].text, audio: audioUrl });
        setSlides([...newSlides]);
      }
      setStatus('আপনার ভিডিও এখন প্রস্তুত!');
    } catch (e: any) {
      console.error(e);
      if (e.message?.includes("Requested entity was not found")) {
        setStatus("API Key এর সমস্যা, আবার ট্রাই করুন।");
        setIsKeySelected(false);
        setIsLaunched(false);
      } else {
        setStatus('কিছু একটা ভুল হয়েছে। ইন্টারন্টে কানেকশন চেক করুন।');
      }
    } finally {
      setLoading(false);
    }
  };

  const play = async () => {
    if (isPlaying || slides.length === 0) return;
    setIsPlaying(true);
    for (let i = 0; i < slides.length; i++) {
      setCurrentIndex(i);
      audioRef.current.src = slides[i].audio;
      await audioRef.current.play();
      await new Promise(r => audioRef.current.onended = r);
    }
    setIsPlaying(false);
    setCurrentIndex(0);
  };

  const download = async () => {
    if (slides.length === 0) return;
    setExporting(true);
    setStatus("ভিডিও ফাইল রেন্ডার হচ্ছে...");

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    canvas.width = ratio.width;
    canvas.height = ratio.height;

    const stream = canvas.captureStream(30);
    const mediaRecorder = new MediaRecorder(stream, { 
      mimeType: 'video/webm;codecs=vp9', 
      videoBitsPerSecond: 8000000 
    });
    const chunks: Blob[] = [];
    mediaRecorder.ondataavailable = (e) => chunks.push(e.data);
    mediaRecorder.onstop = () => {
      const blob = new Blob(chunks, { type: 'video/webm' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Babu_Video_${Date.now()}.webm`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      setExporting(false);
      setStatus("ডাউনলোড সম্পন্ন হয়েছে!");
    };

    mediaRecorder.start();

    for (const slide of slides) {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = slide.image;
      await new Promise<void>(res => {
        img.onload = async () => {
          for (let f = 0; f < 120; f++) {
            ctx.fillStyle = '#000';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            const s = Math.max(canvas.width / img.width, canvas.height / img.height);
            const w = img.width * s, h = img.height * s;
            ctx.drawImage(img, (canvas.width - w) / 2, (canvas.height - h) / 2, w, h);

            const fontSize = Math.floor(canvas.width * 0.045);
            ctx.font = `bold ${fontSize}px 'Inter', sans-serif`;
            ctx.textAlign = 'center';

            const words = slide.text.split(' ');
            let lines: string[] = [], line = '';
            for (let word of words) {
              if (ctx.measureText(line + word).width > canvas.width * 0.8) {
                lines.push(line.trim());
                line = word + ' ';
              } else { line += word + ' '; }
            }
            lines.push(line.trim());

            const boxH = lines.length * fontSize * 1.5 + 40;
            ctx.fillStyle = 'rgba(0,0,0,0.6)';
            ctx.fillRect(0, canvas.height - boxH - 60, canvas.width, boxH);

            ctx.fillStyle = '#FFF';
            lines.forEach((l, idx) => {
              ctx.fillText(l, canvas.width / 2, (canvas.height - boxH - 10) + (idx * fontSize * 1.4));
            });

            await new Promise(rq => requestAnimationFrame(rq));
          }
          res();
        };
      });
    }
    mediaRecorder.stop();
  };

  // Launch / Landing Screen
  if (!isLaunched) {
    return (
      <div className="min-h-screen bg-[#050505] text-white flex flex-col items-center justify-center relative overflow-hidden font-sans">
        {/* Animated Background Gradients */}
        <div className="absolute top-[-20%] left-[-10%] w-[60%] h-[60%] bg-yellow-500/10 rounded-full blur-[150px] animate-pulse" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-500/5 rounded-full blur-[150px]" />

        <div className="max-w-4xl w-full px-6 md:px-12 flex flex-col items-center text-center z-10 space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-1000">
          <div className="space-y-6">
            <div className="inline-flex items-center gap-2 bg-white/5 border border-white/10 px-6 py-2.5 rounded-full mb-4 shadow-xl backdrop-blur-md">
              <Sparkles size={16} className="text-yellow-500 animate-pulse" />
              <span className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-300">Powered by Gemini AI</span>
            </div>

            <h1 className="text-6xl md:text-9xl font-black tracking-tighter leading-[0.85] uppercase">
              BABU <br /><span className="text-transparent bg-clip-text bg-gradient-to-b from-yellow-400 to-yellow-600">STUDIO</span>
            </h1>

            <p className="text-zinc-400 text-lg md:text-2xl max-w-2xl mx-auto font-medium leading-relaxed">
              আপনার কল্পনাকে মুহূর্তেই হাই-কোয়ালিটি <span className="text-white">বাংলা ভিডিওতে</span> রূপান্তর করুন।
            </p>
          </div>

          <div className="flex flex-col items-center gap-8 w-full max-w-md">
            <button 
              onClick={handleLaunch}
              className="group relative w-full bg-yellow-500 text-black font-black py-7 rounded-3xl flex items-center justify-center gap-4 overflow-hidden shadow-[0_0_50px_rgba(250,204,21,0.25)] hover:shadow-[0_0_80px_rgba(250,204,21,0.4)] transition-all hover:-translate-y-1 active:scale-95 active:translate-y-0"
            >
              <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-500" />
              <span className="relative z-10 flex items-center gap-3 text-xl tracking-tight">
                <Wand2 size={24} fill="currentColor" />
                স্টুডিও শুরু করুন
              </span>
              <ChevronRight size={22} className="relative z-10 group-hover:translate-x-2 transition-transform duration-300" />
            </button>

            {isKeySelected === false && (
              <div className="flex items-center gap-4 bg-zinc-900/80 border border-white/5 p-6 rounded-[2rem] text-left backdrop-blur-3xl animate-in zoom-in-95 duration-500">
                <div className="bg-yellow-500/10 p-3 rounded-2xl border border-yellow-500/20">
                  <ShieldCheck className="text-yellow-500" size={24} />
                </div>
                <div className="space-y-1">
                  <p className="text-xs font-black text-white uppercase tracking-widest">API Key দরকার</p>
                  <p className="text-[11px] text-zinc-500 font-medium leading-relaxed">
                    ভিডিও তৈরির জন্য আপনার পেইড এপিআই কি ব্যবহার করতে হবে।
                  </p>
                </div>
              </div>
            )}
          </div>

          <div className="pt-10 grid grid-cols-2 md:grid-cols-3 gap-8 opacity-40 grayscale hover:grayscale-0 transition-all duration-700">
             <div className="flex flex-col items-center gap-2">
               <Video size={24} />
               <span className="text-[10px] font-black uppercase tracking-widest">Cinematic AI</span>
             </div>
             <div className="flex flex-col items-center gap-2">
               <Smartphone size={24} />
               <span className="text-[10px] font-black uppercase tracking-widest">Reels & Shorts</span>
             </div>
             <div className="hidden md:flex flex-col items-center gap-2">
               <Settings2 size={24} />
               <span className="text-[10px] font-black uppercase tracking-widest">High Quality</span>
             </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#050505] text-white selection:bg-yellow-500 selection:text-black font-sans">
      <div className="max-w-6xl mx-auto flex flex-col lg:flex-row h-screen">

        {/* Sidebar / Form */}
        <aside className="w-full lg:w-96 p-6 lg:p-10 border-r border-white/5 flex flex-col gap-8 bg-zinc-900/20 backdrop-blur-xl">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setIsLaunched(false)}>
              <div className="bg-yellow-500 p-2.5 rounded-2xl text-black shadow-lg shadow-yellow-500/20 group-hover:scale-110 transition-transform">
                <Sparkles size={24} fill="currentColor"/>
              </div>
              <div>
                <h1 className="text-xl font-black tracking-tighter uppercase leading-none">Babu Studio</h1>
                <p className="text-[10px] font-bold text-yellow-500 uppercase tracking-widest mt-1">AI Video Creator</p>
              </div>
            </div>
          </div>

          <div className="flex-1 space-y-8 overflow-y-auto pr-2 custom-scrollbar">
            <section className="space-y-4">
              <div className="flex items-center gap-2 text-zinc-500">
                <Layers size={14} />
                <span className="text-[10px] font-black uppercase tracking-widest">ভিডিওর স্ক্রিপ্ট</span>
              </div>
              <textarea 
                className="w-full bg-zinc-900/50 rounded-3xl p-6 text-sm border border-white/5 focus:border-yellow-500/30 focus:ring-4 focus:ring-yellow-500/5 outline-none resize-none placeholder:text-zinc-700 text-zinc-200 transition-all min-h-[120px]"
                placeholder="ভিডিওর জন্য প্রম্পট লিখুন... (যেমন: একটি রহস্যময় বনের সুন্দর গল্প)"
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
              />
            </section>

            <section className="space-y-4">
              <div className="flex items-center gap-2 text-zinc-500">
                <Settings2 size={14} />
                <span className="text-[10px] font-black uppercase tracking-widest">কনফিগারেশন</span>
              </div>

              <div className="grid grid-cols-2 gap-3">
                {RATIOS.map(r => (
                  <button 
                    key={r.id}
                    onClick={() => setRatio(r)}
                    className={`flex flex-col items-center gap-2 p-4 rounded-3xl border transition-all ${ratio.id === r.id ? 'bg-white text-black border-white shadow-xl' : 'bg-zinc-900/50 text-zinc-500 border-white/5 hover:bg-zinc-800'}`}
                  >
                    {r.icon}
                    <span className="text-[10px] font-bold uppercase">{r.name}</span>
                  </button>
                ))}
              </div>

              <div className="space-y-3">
                <div className="relative">
                  <select 
                    className="w-full bg-zinc-900/50 p-5 rounded-2xl border border-white/5 text-[11px] font-black uppercase tracking-widest outline-none cursor-pointer text-zinc-400 appearance-none hover:bg-zinc-800 transition-colors" 
                    value={lang.id} 
                    onChange={(e) => setLang(LANGUAGES.find(l => l.id === e.target.value)!)}
                  >
                    {LANGUAGES.map(l => <option key={l.id} value={l.id}>{l.name}</option>)}
                  </select>
                  <div className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none text-zinc-600">
                    <ArrowRight size={14} />
                  </div>
                </div>
              </div>
            </section>
          </div>

          <button 
            onClick={generate} 
            disabled={loading} 
            className="w-full bg-yellow-500 text-black font-black rounded-2xl py-6 flex items-center justify-center gap-3 hover:bg-yellow-400 active:scale-95 transition-all disabled:opacity-50 shadow-2xl shadow-yellow-500/20"
          >
            {loading ? <Loader2 className="animate-spin" size={20}/> : <RefreshCw size={20} strokeWidth={3}/>}
            {loading ? "তৈরি হচ্ছে..." : "ভিডিও তৈরি করুন"}
          </button>
        </aside>

        {/* Main Preview Area */}
        <main className="flex-1 p-6 lg:p-10 flex flex-col items-center justify-center relative bg-[radial-gradient(circle_at_center,_#111_0%,_#050505_100%)]">
          <div 
            className="relative w-full max-w-2xl bg-zinc-900 rounded-[3rem] overflow-hidden border border-white/5 shadow-[0_0_100px_rgba(0,0,0,0.5)] flex flex-col items-center justify-center group"
            style={{ 
              aspectRatio: ratio.id === '9:16' ? '9/16' : '16/9', 
              maxHeight: '80vh' 
            }}
          >
            {slides.length > 0 ? (
              <>
                <img src={slides[currentIndex].image} className="w-full h-full object-cover transition-opacity duration-700 ease-in-out" alt="preview" />
                <div className="absolute inset-x-0 bottom-0 p-12 bg-gradient-to-t from-black via-black/80 to-transparent">
                  <p className="text-center font-bold text-2xl lg:text-3xl text-white drop-shadow-2xl leading-tight animate-in fade-in slide-in-from-bottom-4 duration-500">{slides[currentIndex].text}</p>
                </div>

                {!isPlaying && (
                  <button onClick={play} className="absolute inset-0 flex items-center justify-center bg-black/40 group-hover:bg-black/20 transition-all backdrop-blur-[2px]">
                    <div className="bg-white text-black p-8 rounded-full shadow-2xl scale-100 hover:scale-110 active:scale-90 transition-all duration-300">
                      <Play fill="currentColor" size={48} />
                    </div>
                  </button>
                )}
              </>
            ) : (
              <div className="text-zinc-800 flex flex-col items-center gap-6">
                <div className="bg-zinc-900 p-12 rounded-full border border-white/5 shadow-inner">
                  <Video size={64} className="opacity-10" />
                </div>
                <div className="text-center space-y-2">
                  <p className="text-[12px] font-black uppercase tracking-[0.6em] opacity-30">PREVIEW AREA</p>
                  <p className="text-[10px] font-medium text-zinc-600 uppercase tracking-widest">আপনার ভিডিও এখানে দেখা যাবে</p>
                </div>
              </div>
            )}

            {loading && (
              <div className="absolute inset-0 bg-black/90 backdrop-blur-2xl flex flex-col items-center justify-center gap-10 z-50">
                <div className="relative">
                  <div className="w-24 h-24 rounded-full border-t-4 border-yellow-500 animate-spin" />
                  <div className="absolute inset-0 flex items-center justify-center">
                    <Sparkles className="text-yellow-500 animate-pulse" size={32} />
                  </div>
                </div>
                <div className="text-center space-y-3 px-10">
                  <p className="text-[10px] text-zinc-500 font-black uppercase tracking-[0.4em] animate-pulse">Babu Engine Processing</p>
                  <p className="text-xl font-bold text-white max-w-xs">{status}</p>
                </div>
              </div>
            )}
          </div>

          {slides.length > 0 && !loading && (
            <div className="mt-8 flex gap-4 animate-in fade-in zoom-in duration-700">
              <button 
                onClick={download} 
                disabled={exporting} 
                className="bg-white text-black px-10 py-5 rounded-2xl font-black flex items-center gap-3 hover:bg-zinc-200 transition-all active:scale-95 shadow-2xl"
              >
                {exporting ? <Loader2 className="animate-spin" size={22} /> : <Download size={22} strokeWidth={3} />}
                {exporting ? "সেভ হচ্ছে..." : "ডাউনলোড করুন"}
              </button>
              <button 
                onClick={() => setSlides([])} 
                className="bg-zinc-900 border border-white/5 text-zinc-500 px-6 py-5 rounded-2xl font-black hover:text-white transition-all"
              >
                <RefreshCw size={22} />
              </button>
            </div>
          )}

          {status && !loading && slides.length > 0 && (
            <div className="absolute bottom-10 flex items-center gap-2 bg-green-500/10 text-green-500 px-4 py-2 rounded-full border border-green-500/20">
              <CheckCircle2 size={14} />
              <span className="text-[10px] font-black uppercase tracking-widest">{status}</span>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { 
  Play, Video, Download, Loader2, RefreshCw, Smartphone, Monitor, ShieldCheck, Zap,
  Sparkles, Layers, Settings2, ArrowRight, CheckCircle2, ChevronRight, Wand2,
  Volume2, Type, Image as ImageIcon, Plus, Trash2, Edit3, Music
} from 'lucide-react';
import { GeminiService } from './services/geminiService';

const LANGUAGES = [
  { id: 'bn', name: 'Bengali (বাংলা)', voice: 'Kore', label: 'বাংলা (ভারত)' },
  { id: 'en', name: 'English', voice: 'Puck', label: 'English (US)' },
];

const RATIOS = [
  { id: '9:16', name: 'Portrait', width: 720, height: 1280, icon: <Smartphone size={16} /> },
  { id: '16:9', name: 'Landscape', width: 1280, height: 720, icon: <Monitor size={16} /> }
];

const App: React.FC = () => {
  const [isLaunched, setIsLaunched] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [scenes, setScenes] = useState<any[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [status, setStatus] = useState('');
  const [exporting, setExporting] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [ratio, setRatio] = useState(RATIOS[0]);
  const [lang, setLang] = useState(LANGUAGES[0]);
  const [isKeySelected, setIsKeySelected] = useState<boolean | null>(null);

  const audioRef = useRef(new Audio());

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        try {
          const hasKey = await window.aistudio.hasSelectedApiKey();
          setIsKeySelected(hasKey);
        } catch (e) {
          setIsKeySelected(false);
        }
      } else {
        setIsKeySelected(true);
      }
    };
    checkKey();
  }, []);

  const handleLaunch = async () => {
    if (isKeySelected === false) {
      if (window.aistudio?.openSelectKey) {
        await window.aistudio.openSelectKey();
        setIsKeySelected(true);
      }
    }
    setIsLaunched(true);
  };

  const pcmToWav = (pcmData: Int16Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + pcmData.length * 2);
    const view = new DataView(buffer);
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i));
    };
    writeString(0, 'RIFF');
    view.setUint32(4, 32 + pcmData.length * 2, true);
    writeString(8, 'WAVE');
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(36, 'data');
    view.setUint32(40, pcmData.length * 2, true);
    for (let i = 0; i < pcmData.length; i++) view.setInt16(44 + i * 2, pcmData[i], true);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const generate = async () => {
    if (!prompt.trim()) {
        setStatus("দয়া করে আপনার বিষয়বস্তু লিখুন!");
        return;
    }
    setLoading(true);
    setStatus('স্ক্রিপ্ট এনালাইসিস হচ্ছে...');
    setScenes([]);
    setCurrentIndex(0);

    try {
      const generatedScenes = await GeminiService.generateScript(prompt, lang.name, ratio.id);

      const newScenes: any[] = [];
      for (let i = 0; i < generatedScenes.length; i++) {
        setStatus(`সিন ${i + 1}/${generatedScenes.length} প্রসেসিং হচ্ছে...`);

        // Parallel fetch for media components
        const [imgUrl, audioBytes] = await Promise.all([
          GeminiService.generateImage(generatedScenes[i].img_prompt, ratio.id),
          GeminiService.generateAudio(generatedScenes[i].text, lang.voice)
        ]);

        const wavBlob = pcmToWav(new Int16Array(audioBytes.buffer), 24000);
        const audioUrl = URL.createObjectURL(wavBlob);

        newScenes.push({ 
          image: imgUrl, 
          text: generatedScenes[i].text, 
          audio: audioUrl,
          id: Date.now() + i
        });
        setScenes([...newScenes]);
      }
      setStatus('প্রজেক্ট প্রস্তুত!');
    } catch (e: any) {
      console.error(e);
      if (e.message?.includes("Requested entity was not found")) {
        setStatus("API Key এর সমস্যা, আবার ট্রাই করুন।");
        setIsKeySelected(false);
        setIsLaunched(false);
      } else {
        setStatus('কিছু একটা ভুল হয়েছে। ইন্টারন্টে কানেকশন চেক করুন।');
      }
    } finally {
      setLoading(false);
    }
  };

  const playPreview = async () => {
    if (isPlaying || scenes.length === 0) return;
    setIsPlaying(true);
    for (let i = 0; i < scenes.length; i++) {
      setCurrentIndex(i);
      audioRef.current.src = scenes[i].audio;
      await audioRef.current.play();
      await new Promise(r => audioRef.current.onended = r);
    }
    setIsPlaying(false);
    setCurrentIndex(0);
  };

  const exportVideo = async () => {
    if (scenes.length === 0) return;
    setExporting(true);
    setStatus("হাই-কোয়ালিটি ভিডিও রেন্ডার হচ্ছে...");

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    canvas.width = ratio.width;
    canvas.height = ratio.height;

    const stream = canvas.captureStream(30);
    const mediaRecorder = new MediaRecorder(stream, { 
      mimeType: 'video/webm;codecs=vp9', 
      videoBitsPerSecond: 12000000 
    });
    const chunks: Blob[] = [];
    mediaRecorder.ondataavailable = (e) => chunks.push(e.data);
    mediaRecorder.onstop = () => {
      const blob = new Blob(chunks, { type: 'video/webm' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Babu_Studio_${Date.now()}.webm`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      setExporting(false);
      setStatus("সফলভাবে ডাউনলোড হয়েছে!");
    };

    mediaRecorder.start();

    for (const scene of scenes) {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = scene.image;
      await new Promise<void>(res => {
        img.onload = async () => {
          // Play each scene for roughly 4 seconds
          for (let f = 0; f < 120; f++) {
            ctx.fillStyle = '#050505';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            const s = Math.max(canvas.width / img.width, canvas.height / img.height);
            const w = img.width * s, h = img.height * s;
            ctx.drawImage(img, (canvas.width - w) / 2, (canvas.height - h) / 2, w, h);

            // Subtitle Styling (Fliki Style)
            const fontSize = Math.floor(canvas.width * 0.05);
            ctx.font = `bold ${fontSize}px 'Inter', sans-serif`;
            ctx.textAlign = 'center';

            const words = scene.text.split(' ');
            let lines: string[] = [], line = '';
            for (let word of words) {
              if (ctx.measureText(line + word).width > canvas.width * 0.85) {
                lines.push(line.trim());
                line = word + ' ';
              } else { line += word + ' '; }
            }
            lines.push(line.trim());

            const boxPadding = 40;
            const boxH = lines.length * fontSize * 1.4 + boxPadding;

            // Subtitle Backdrop
            ctx.fillStyle = 'rgba(0,0,0,0.7)';
            ctx.beginPath();
            ctx.roundRect(canvas.width * 0.075, canvas.height - boxH - 80, canvas.width * 0.85, boxH, 20);
            ctx.fill();

            ctx.fillStyle = '#facc15'; // Primary Yellow
            lines.forEach((l, idx) => {
              ctx.fillText(l, canvas.width / 2, (canvas.height - boxH - 20) + (idx * fontSize * 1.3));
            });

            await new Promise(rq => requestAnimationFrame(rq));
          }
          res();
        };
      });
    }
    mediaRecorder.stop();
  };

  // 1. Cinematic Launch Screen
  if (!isLaunched) {
    return (
      <div className="min-h-screen bg-[#050505] text-white flex flex-col items-center justify-center relative overflow-hidden font-sans">
        <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-yellow-500/10 rounded-full blur-[160px] animate-pulse" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-600/5 rounded-full blur-[160px]" />

        <div className="max-w-4xl w-full px-6 flex flex-col items-center text-center z-10 space-y-10 animate-in fade-in slide-in-from-bottom-12 duration-1000">
          <div className="space-y-4">
            <div className="inline-flex items-center gap-2 bg-white/5 border border-white/10 px-5 py-2 rounded-full mb-4 shadow-2xl backdrop-blur-xl">
              <Sparkles size={14} className="text-yellow-500" />
              <span className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-400">Next-Gen Video Studio</span>
            </div>

            <h1 className="text-7xl md:text-[10rem] font-black tracking-tighter leading-[0.8] uppercase flex flex-col">
              BABU 
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 via-yellow-200 to-yellow-600 drop-shadow-sm">STUDIO</span>
