  // 2. Professional Video Editor Interface
  return (
    <div className="min-h-screen bg-[#050505] text-white selection:bg-yellow-500 selection:text-black font-sans flex flex-col h-screen overflow-hidden">

      {/* Header Bar */}
      <header className="h-16 border-b border-white/5 px-6 flex items-center justify-between bg-[#050505]/80 backdrop-blur-xl z-50">
        <div className="flex items-center gap-4">
          <div className="bg-yellow-500 p-2 rounded-xl text-black shadow-lg shadow-yellow-500/20 cursor-pointer hover:rotate-12 transition-transform" onClick={() => setIsLaunched(false)}>
            <Sparkles size={20} fill="currentColor"/>
          </div>
          <div className="hidden sm:block">
            <h1 className="text-sm font-black tracking-tighter uppercase leading-none">Babu Studio</h1>
