          </div>

          {/* Bottom Editor Bar */}
          <div className="h-64 border-t border-white/5 bg-[#050505]/50 backdrop-blur-xl p-8 flex gap-10">
             <div className="w-96 space-y-4">
                <div className="flex items-center gap-2 text-zinc-500">
                  <Edit3 size={14} />
                  <span className="text-[10px] font-black uppercase tracking-widest">Video Prompt</span>
                </div>
                <div className="relative group">
                  <textarea 
                    className="w-full bg-zinc-900/50 rounded-3xl p-6 text-sm border border-white/5 focus:border-yellow-500/40 focus:ring-4 focus:ring-yellow-500/5 outline-none resize-none placeholder:text-zinc-700 text-zinc-200 transition-all h-32 custom-scrollbar"
                    placeholder="ভিডিওর জন্য স্ক্রিপ্ট বা আইডিয়া দিন..."
