                  <div className="grid grid-cols-2 gap-4">
                    <select 
                      className="bg-zinc-900/50 p-5 rounded-2xl border border-white/5 text-[11px] font-black uppercase tracking-widest outline-none cursor-pointer text-zinc-400 hover:bg-zinc-800 transition-colors appearance-none" 
                      value={lang.id} 
                      onChange={(e) => setLang(LANGUAGES.find(l => l.id === e.target.value)!)}
                    >
                      {LANGUAGES.map(l => <option key={l.id} value={l.id}>{l.label}</option>)}
                    </select>
                    <div className="bg-zinc-900/50 p-5 rounded-2xl border border-white/10 flex items-center justify-between">
                       <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Voice: {lang.voice}</span>
