                  <p className="text-[9px] text-zinc-600 font-medium">Gemini TTS delivers high-fidelity Bengali narration with natural prosody.</p>
                </div>

                <div className="w-64 flex flex-col justify-end">
                   <button 
                    onClick={generate} 
                    disabled={loading} 
                    className="w-full h-24 bg-yellow-500 text-black font-black rounded-[2rem] flex items-center justify-center gap-3 hover:bg-yellow-400 active:scale-95 transition-all disabled:opacity-50 shadow-2xl shadow-yellow-500/10"
                  >
                    {loading ? <Loader2 className="animate-spin" size={24}/> : <Zap size={24} fill="currentColor"/>}
                    <span className="text-lg">ভিডিও তৈরি করুন</span>
                  </button>
                </div>
             </div>
          </div>
        </main>
      </div>

      {/* Small Status Toast */}
      {status && !loading && (
        <div className="fixed bottom-6 right-6 flex items-center gap-3 bg-zinc-900 border border-white/10 px-6 py-3 rounded-full shadow-2xl animate-in slide-in-from-right-10 z-[100]">
          <CheckCircle2 size={16} className="text-yellow-500" />
          <span className="text-[10px] font-black uppercase tracking-widest text-zinc-200">{status}</span>
        </div>
      )}
