        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-600/5 rounded-full blur-[160px]" />

        <div className="max-w-4xl w-full px-6 flex flex-col items-center text-center z-10 space-y-12 animate-in fade-in slide-in-from-bottom-10 duration-1000">
