                      value={lang.id} 
                      onChange={(e) => setLang(LANGUAGES.find(l => l.id === e.target.value)!)}
                    >
                      {LANGUAGES.map(l => <option key={l.id} value={l.id}>{l.label}</option>)}
                    </select>
                    <div className="bg-zinc-900/50 p-5 rounded-2xl border border-white/10 flex items-center justify-between opacity-50">
                       <span className="text-[10px] font-black uppercase tracking-widest">Voice: {lang.voice}</span>
                       <Music size={14} />
                    </div>
                  </div>
                </div>

                <div className="w-64 flex flex-col justify-end">
                   <button 
                    onClick={generate} 
                    disabled={loading} 
                    className="w-full h-24 bg-yellow-500 text-black font-black rounded-[2rem] flex items-center justify-center gap-3 hover:bg-yellow-400 transition-all disabled:opacity-50 shadow-2xl"
                  >
                    {loading ? <Loader2 className="animate-spin" size={24}/> : <Zap size={24} fill="currentColor"/>}
                    <span className="text-xl">তৈরি করুন</span>
                  </button>
