                <>
                  <img src={scenes[currentIndex].image} className="w-full h-full object-cover animate-in fade-in duration-700" alt="preview" />
                  <div className="absolute inset-x-0 bottom-0 p-10 bg-gradient-to-t from-black via-black/80 to-transparent">
                    <p className="text-center font-bold text-2xl md:text-3xl text-white drop-shadow-2xl">{scenes[currentIndex].text}</p>
                  </div>

                  {!isPlaying && (
                    <button onClick={playPreview} className="absolute inset-0 flex items-center justify-center bg-black/20 group-hover:bg-black/10 transition-all backdrop-blur-[1px]">
                      <div className="bg-white text-black p-8 rounded-full shadow-2xl scale-100 hover:scale-110 transition-all">
                        <Play fill="currentColor" size={40} />
