                  <div className="text-center px-12">
                    <p className="text-[10px] text-zinc-500 font-black uppercase tracking-[0.4em] mb-2 animate-pulse">Processing Video</p>
                    <p className="text-lg font-bold text-white">{status}</p>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Bottom Bar: Editor Controls */}
          <div className="h-64 border-t border-white/5 bg-zinc-900/40 backdrop-blur-3xl p-8 flex gap-10">
             <div className="w-96 space-y-4">
