                </div>
                <textarea 
                  className="w-full bg-zinc-900/50 rounded-2xl p-6 text-sm border border-white/5 focus:border-yellow-500/40 outline-none resize-none placeholder:text-zinc-700 text-zinc-200 h-32 transition-all"
                  placeholder="আপনার ভিডিও আইডিয়া লিখুন... যেমন: বৃষ্টির দিনে জানালার পাশে কফি খাওয়ার একটি সুন্দর দৃশ্য।"
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                />
             </div>

             <div className="flex-1 flex gap-10">
                <div className="space-y-4 flex-1">
                  <div className="flex items-center gap-2 text-zinc-500">
                    <Settings2 size={14} />
                    <span className="text-[10px] font-black uppercase tracking-widest">Format & Voice</span>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="flex gap-2 bg-zinc-900/50 p-1.5 rounded-2xl border border-white/5">
