                        <button key={r.id} onClick={() => setRatio(r)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl transition-all ${ratio.id === r.id ? 'bg-white text-black' : 'text-zinc-500 hover:text-white'}`}>
                          {r.icon}
                        </button>
                      ))}
                    </div>
                    <select 
                      className="bg-zinc-900/50 p-4 rounded-2xl border border-white/5 text-[11px] font-black uppercase tracking-widest outline-none cursor-pointer text-zinc-400 hover:bg-zinc-800 appearance-none text-center" 
                      value={lang.id} 
                      onChange={(e) => setLang(LANGUAGES.find(l => l.id === e.target.value)!)}
                    >
                      {LANGUAGES.map(l => <option key={l.id} value={l.id}>{l.label}</option>)}
                    </select>
                  </div>
                  <div className="flex items-center gap-3 bg-zinc-900/50 p-4 rounded-2xl border border-white/5 opacity-50">
                    <Volume2 size={16} className="text-zinc-500" />
                    <span className="text-[10px] font-black uppercase tracking-widest text-zinc-400">Natural Voice: {lang.voice}</span>
                  </div>
                </div>

                <div className="w-64 flex flex-col justify-end pb-1">
                   <button 
                    onClick={generate} 
                    disabled={loading} 
                    className="w-full h-24 bg-yellow-500 text-black font-black rounded-[2rem] flex items-center justify-center gap-3 hover:bg-yellow-400 transition-all disabled:opacity-50 shadow-2xl shadow-yellow-500/10"
                  >
                    {loading ? <Loader2 className="animate-spin" size={24}/> : <Zap size={24} fill="currentColor"/>}
                    <span className="text-xl">তৈরি করুন</span>
                  </button>
                </div>
             </div>
          </div>
        </main>
      </div>

      {status && !loading && scenes.length > 0 && (
        <div className="fixed bottom-6 right-6 bg-zinc-900 border border-white/10 px-6 py-3 rounded-full shadow-2xl animate-in slide-in-from-right-10 flex items-center gap-3">
          <CheckCircle2 size={16} className="text-yellow-500" />
          <span className="text-[10px] font-black uppercase tracking-widest">{status}</span>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { 
  Play, Video, Download, Loader2, RefreshCw, Smartphone, Monitor, ShieldCheck, Zap,
  Sparkles, Layers, Settings2, ArrowRight, CheckCircle2, Wand2,
  Volume2, Type, Image as ImageIcon, Plus, Edit3, Music, ChevronLeft, User, Users
} from 'lucide-react';
import { GeminiService } from './services/geminiService';

const LANGUAGES = [
  { id: 'Bengali', name: 'Bengali (বাংলা)', label: 'বাংলা' },
  { id: 'Hindi', name: 'Hindi (हिन्दी)', label: 'हिन्दी' },
  { id: 'English', name: 'English', label: 'English' },
];

const GENDERS = [
  { id: 'Male', label: 'পুরুষ (Male)', voice: 'Fenrir' },
  { id: 'Female', label: 'মহিলা (Female)', voice: 'Zephyr' },
];

const RATIOS = [
  { id: '9:16', name: 'Portrait', width: 720, height: 1280, icon: <Smartphone size={16} /> },
  { id: '16:9', name: 'Landscape', width: 1280, height: 720, icon: <Monitor size={16} /> }
];

const App: React.FC = () => {
  const [isLaunched, setIsLaunched] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [scenes, setScenes] = useState<any[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [status, setStatus] = useState('');
  const [exporting, setExporting] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [ratio, setRatio] = useState(RATIOS[0]);
  const [lang, setLang] = useState(LANGUAGES[0]);
  const [gender, setGender] = useState(GENDERS[1]); // Default Female
  const [isKeySelected, setIsKeySelected] = useState<boolean | null>(null);

  const audioRef = useRef(new Audio());

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        try {
          const hasKey = await window.aistudio.hasSelectedApiKey();
          setIsKeySelected(hasKey);
        } catch (e) {
          setIsKeySelected(false);
        }
      } else {
        setIsKeySelected(true);
      }
    };
    checkKey();
  }, []);

  const handleLaunch = async () => {
    if (isKeySelected === false) {
      if (window.aistudio?.openSelectKey) {
        await window.aistudio.openSelectKey();
        setIsKeySelected(true);
      }
    }
    setIsLaunched(true);
  };

  const pcmToWav = (pcmData: Int16Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + pcmData.length * 2);
    const view = new DataView(buffer);
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i));
    };
    writeString(0, 'RIFF');
    view.setUint32(4, 32 + pcmData.length * 2, true);
    writeString(8, 'WAVE');
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(36, 'data');
    view.setUint32(40, pcmData.length * 2, true);
    for (let i = 0; i < pcmData.length; i++) view.setInt16(44 + i * 2, pcmData[i], true);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const generate = async () => {
    if (!prompt.trim()) {
        setStatus("দয়া করে আপনার বিষয়বস্তু লিখুন!");
        return;
    }
    setLoading(true);
    setStatus('স্ক্রিপ্ট এনালাইসিস হচ্ছে...');
    setScenes([]);
    setCurrentIndex(0);

    try {
      // 1. Generate Script
      const generatedScenes = await GeminiService.generateScript(prompt, lang.name, ratio.id);

      const newScenes: any[] = [];
      for (let i = 0; i < generatedScenes.length; i++) {
        setStatus(`সিন ${i + 1}/${generatedScenes.length} তৈরি হচ্ছে...`);

        // 2. Parallel Generate Assets
        const [imgUrl, audioBytes] = await Promise.all([
          GeminiService.generateImage(generatedScenes[i].img_prompt, ratio.id),
          GeminiService.generateAudio(generatedScenes[i].text, gender.voice)
        ]);

        const wavBlob = pcmToWav(new Int16Array(audioBytes.buffer), 24000);
        const audioUrl = URL.createObjectURL(wavBlob);

        newScenes.push({ 
          image: imgUrl, 
          text: generatedScenes[i].text, 
          audio: audioUrl,
          id: Date.now() + i
        });
        setScenes([...newScenes]);
      }
      setStatus('আপনার ভিডিও এখন প্রস্তুত!');
    } catch (e: any) {
      console.error(e);
      setStatus('ভুল হয়েছে, আবার চেষ্টা করুন।');
    } finally {
      setLoading(false);
    }
  };

  const playPreview = async () => {
    if (isPlaying || scenes.length === 0) return;
    setIsPlaying(true);
    for (let i = 0; i < scenes.length; i++) {
      setCurrentIndex(i);
      audioRef.current.src = scenes[i].audio;
      await audioRef.current.play();
      await new Promise(r => audioRef.current.onended = r);
    }
    setIsPlaying(false);
    setCurrentIndex(0);
  };

  const exportVideo = async () => {
    if (scenes.length === 0) return;
    setExporting(true);
    setStatus("ভিডিও ফাইল রেন্ডার হচ্ছে...");

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    canvas.width = ratio.width;
    canvas.height = ratio.height;

    const stream = canvas.captureStream(30);
    const mediaRecorder = new MediaRecorder(stream, { 
      mimeType: 'video/webm;codecs=vp9', 
      videoBitsPerSecond: 12000000 
    });
    const chunks: Blob[] = [];
    mediaRecorder.ondataavailable = (e) => chunks.push(e.data);
    mediaRecorder.onstop = () => {
      const blob = new Blob(chunks, { type: 'video/webm' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Babu_Studio_AI_${Date.now()}.webm`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      setExporting(false);
      setStatus("ডাউনলোড সম্পন্ন হয়েছে!");
    };

    mediaRecorder.start();

    for (const scene of scenes) {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = scene.image;
      await new Promise<void>(res => {
        img.onload = async () => {
          // Calculate duration based on audio if possible, or fixed 4 seconds
          for (let f = 0; f < 120; f++) {
            ctx.fillStyle = '#050505';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            const s = Math.max(canvas.width / img.width, canvas.height / img.height);
            const w = img.width * s, h = img.height * s;
            ctx.drawImage(img, (canvas.width - w) / 2, (canvas.height - h) / 2, w, h);

            const fontSize = Math.floor(canvas.width * 0.05);
            ctx.font = `bold ${fontSize}px 'Inter', sans-serif`;
            ctx.textAlign = 'center';

            const words = scene.text.split(' ');
            let lines: string[] = [], line = '';
            for (let word of words) {
              if (ctx.measureText(line + word).width > canvas.width * 0.85) {
                lines.push(line.trim());
                line = word + ' ';
              } else { line += word + ' '; }
            }
            lines.push(line.trim());

            const boxPadding = 30;
            const boxH = lines.length * fontSize * 1.5 + boxPadding;

            ctx.fillStyle = 'rgba(0,0,0,0.85)';
            ctx.beginPath();
            ctx.roundRect(canvas.width * 0.05, canvas.height - boxH - 100, canvas.width * 0.9, boxH, 20);
            ctx.fill();

            ctx.fillStyle = '#facc15';
            lines.forEach((l, idx) => {
              ctx.fillText(l, canvas.width / 2, (canvas.height - boxH - 40) + (idx * fontSize * 1.4));
            });

            await new Promise(rq => requestAnimationFrame(rq));
          }
          res();
        };
      });
    }
    mediaRecorder.stop();
  };

  if (!isLaunched) {
    return (
      <div className="min-h-screen bg-[#050505] text-white flex flex-col items-center justify-center relative overflow-hidden font-sans">
        <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-yellow-500/10 rounded-full blur-[160px]" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-600/5 rounded-full blur-[160px]" />

        <div className="max-w-4xl w-full px-6 flex flex-col items-center text-center z-10 animate-in fade-in slide-in-from-bottom-10 duration-1000">
          <div className="inline-flex items-center gap-2 bg-white/5 border border-white/10 px-6 py-2 rounded-full mb-8 backdrop-blur-xl">
            <Sparkles size={14} className="text-yellow-500" />
            <span className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-400">Next-Gen Video Production</span>
          </div>

          <h1 className="text-7xl md:text-9xl font-black tracking-tighter leading-[0.8] uppercase mb-8">
            BABU <span className="text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-yellow-600">STUDIO</span>
          </h1>

          <p className="text-zinc-400 text-lg md:text-2xl max-w-2xl mx-auto font-medium leading-relaxed mb-12">
            আপনার চিন্তাকে <span className="text-white">প্রফেশনাল AI ভিডিওতে</span> রূপান্তর করুন। <br className="hidden md:block"/> টেক্সট দিন, ভিডিও নিন।
          </p>

          <button 
            onClick={handleLaunch}
            className="group relative bg-white text-black font-black px-12 py-8 rounded-[2rem] flex items-center gap-4 shadow-2xl hover:-translate-y-2 transition-all active:scale-95"
          >
            <div className="absolute inset-0 bg-yellow-500 translate-x-full group-hover:translate-x-0 transition-transform duration-500" />
            <span className="relative z-10 flex items-center gap-3 text-xl tracking-tight">
              স্টুডিও শুরু করুন
              <ArrowRight size={24} />
            </span>
          </button>

          {isKeySelected === false && (
            <div className="mt-12 flex items-center gap-4 bg-zinc-900/50 border border-white/5 p-6 rounded-[2rem] text-left">
              <ShieldCheck className="text-yellow-500 shrink-0" size={24} />
              <div className="space-y-1">
                <p className="text-xs font-black text-white uppercase tracking-widest">Setup Required</p>
                <p className="text-[11px] text-zinc-500 leading-relaxed">এই অ্যাপটি ব্যবহারের জন্য আপনার নিজস্ব API Key প্রয়োজন।</p>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#050505] text-white flex flex-col h-screen overflow-hidden selection:bg-yellow-500 selection:text-black">

      {/* Header */}
      <header className="h-16 border-b border-white/5 px-6 flex items-center justify-between bg-zinc-900/10 backdrop-blur-2xl z-50">
        <div className="flex items-center gap-4">
          <button onClick={() => setIsLaunched(false)} className="p-2 hover:bg-white/5 rounded-xl text-zinc-500 transition-colors">
            <ChevronLeft size={20} />
          </button>
          <div className="flex items-center gap-3">
            <div className="bg-yellow-500 p-1.5 rounded-lg text-black">
              <Sparkles size={16} fill="currentColor"/>
            </div>
            <h1 className="text-sm font-black tracking-widest uppercase">Babu Studio</h1>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {scenes.length > 0 && (
            <button 
              onClick={exportVideo}
              disabled={exporting || loading}
              className="bg-white text-black px-6 py-2.5 rounded-full text-[10px] font-black flex items-center gap-2 hover:bg-zinc-200 transition-all disabled:opacity-30 shadow-xl"
            >
              {exporting ? <Loader2 className="animate-spin" size={14} /> : <Download size={14} strokeWidth={3} />}
              {exporting ? "SAVING..." : "DOWNLOAD VIDEO"}
            </button>
          )}
          <div className="w-8 h-8 rounded-full bg-zinc-800 border border-white/10" />
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden">

        {/* Sidebar: Scenes */}
        <aside className="w-80 border-r border-white/5 flex flex-col bg-zinc-900/5 overflow-y-auto custom-scrollbar">
          <div className="p-6 space-y-6">
            <div className="flex items-center justify-between text-zinc-500">
              <span className="text-[10px] font-black uppercase tracking-widest">Scenes</span>
              <span className="text-[10px] font-bold bg-zinc-800 px-2 py-0.5 rounded">{scenes.length}</span>
            </div>

            <div className="space-y-4">
              {scenes.length > 0 ? (
                scenes.map((scene, idx) => (
                  <div 
                    key={scene.id}
                    onClick={() => setCurrentIndex(idx)}
                    className={`group p-4 rounded-3xl border transition-all cursor-pointer ${currentIndex === idx ? 'bg-zinc-900 border-white/10 ring-1 ring-yellow-500/20 shadow-2xl' : 'bg-transparent border-white/5 hover:bg-white/5'}`}
                  >
                    <div className="flex gap-4">
                      <div className="relative w-16 h-16 rounded-2xl overflow-hidden bg-zinc-800 shrink-0 border border-white/5">
                        <img src={scene.image} className="w-full h-full object-cover" alt="scene preview" />
                        <div className="absolute inset-0 bg-black/40 flex items-center justify-center text-[10px] font-black">{idx + 1}</div>
                      </div>
                      <div className="flex-1 overflow-hidden">
                        <p className="text-[11px] text-zinc-400 line-clamp-3 leading-relaxed font-medium">{scene.text}</p>
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="py-24 text-center opacity-20 flex flex-col items-center gap-4">
                   <div className="p-8 rounded-full bg-zinc-900 border border-white/5">
                    <Layers size={40} strokeWidth={1} />
                   </div>
                   <p className="text-[10px] font-black uppercase tracking-widest">No Scenes Yet</p>
                </div>
              )}
            </div>
          </div>
        </aside>

        {/* Center: Preview Area */}
        <main className="flex-1 flex flex-col bg-[radial-gradient(circle_at_center,_#111_0%,_#050505_100%)] overflow-hidden">
          <div className="flex-1 p-8 flex flex-col items-center justify-center relative">
            <div 
