import { GoogleGenAI, Modality } from "@google/genai";

export interface Scene {
  image: string;
  text: string;
  audio: Uint8Array;
}

export class GeminiService {
  private static decode(base64: string) {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  }

  static async generateScript(prompt: string, lang: string, ratio: string): Promise<any[]> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const systemInstruction = `You are an elite video scriptwriter and director. 
    Create a cinematic 3-scene video storyboard in the language: ${lang} based on the user prompt: "${prompt}".

    CRITICAL RULES:
    1. The "text" field MUST be in ${lang}. This is for narration and subtitles. (Max 15 words per scene).
    2. The "img_prompt" field MUST be in English. It should be a highly descriptive, cinematic prompt for a high-quality AI image generator, optimized for a ${ratio} aspect ratio.
    3. Ensure a logical narrative flow between scenes.

    Return ONLY valid JSON in this format: 
    { "scenes": [{ "img_prompt": "string", "text": "string" }] }`;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          systemInstruction,
          responseMimeType: "application/json",
          temperature: 0.75
        }
      });

      const textOutput = response.text || '{}';
      const data = JSON.parse(textOutput);
      return data.scenes || [];
    } catch (e: any) {
      console.error("Script generation failed:", e);
      throw e;
    }
  }

  static async generateImage(prompt: string, ratio: string): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      // Primary High Quality Generation
      const response = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: `Cinematic masterpiece photography, hyper-realistic, 8k, professional cinematic lighting, shallow depth of field, dramatic composition: ${prompt}`,
        config: {
          numberOfImages: 1,
          outputMimeType: 'image/jpeg',
          aspectRatio: ratio === '16:9' ? '16:9' : '9:16',
        },
      });

      const base64Image = response.generatedImages[0].image.imageBytes;
      return `data:image/jpeg;base64,${base64Image}`;
    } catch (e: any) {
      console.warn("Imagen 4.0 failed or unavailable, using Gemini 3 Pro Image fallback...");
      const fallback = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: { parts: [{ text: `Cinematic award-winning photography, extremely detailed, photorealistic: ${prompt}` }] },
        config: {
          imageConfig: { 
            aspectRatio: ratio === '16:9' ? '16:9' : '9:16',
            imageSize: "1K"
          }
        }
      });
      const part = fallback.candidates?.[0]?.content?.parts.find(p => p.inlineData);
      if (!part?.inlineData?.data) throw new Error("Image generation failed completely.");
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  static async generateAudio(text: string, voiceName: string): Promise<Uint8Array> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName },
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (!base64Audio) throw new Error("Audio generation failed");
      return GeminiService.decode(base64Audio);
    } catch (e: any) {
      console.error("Audio generation failed:", e);
      throw e;
    }
  }
}

