import { GoogleGenAI, Modality } from "@google/genai";

export interface Scene {
  images: string[];
  text: string;
  audio: Uint8Array;
}

export class GeminiService {
  private static decode(base64: string) {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  }

  static async generateScript(prompt: string, lang: string, ratio: string): Promise<any[]> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const systemInstruction = `You are an elite video scriptwriter. 
    Create a cinematic 3-scene video script in ${lang} based on: "${prompt}".

    RULES:
    1. "text" field: MUST be in ${lang}. Max 12 words.
    2. "img_prompts" field: Provide exactly 4 high-quality English prompts for images.
    3. Optimized for ${ratio} aspect ratio.

    Return ONLY JSON: { "scenes": [{ "img_prompts": ["p1", "p2", "p3", "p4"], "text": "text" }] }`;

    try {
      const response = await ai.models.generateContent({
        // Switched to Flash for better quota availability and speed
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          systemInstruction,
          responseMimeType: "application/json",
          temperature: 0.7
        }
      });

      const textOutput = response.text || '{}';
      const data = JSON.parse(textOutput);
      return data.scenes || [];
    } catch (e: any) {
      console.error("Script generation failed:", e);
      throw e;
    }
  }

  static async generateImage(prompt: string, ratio: string): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const response = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: `Professional cinematic photography, 8k, photorealistic: ${prompt}`,
        config: {
          numberOfImages: 1,
          outputMimeType: 'image/jpeg',
          aspectRatio: ratio === '16:9' ? '16:9' : '9:16',
        },
      });

      const base64Image = response.generatedImages[0].image.imageBytes;
      return `data:image/jpeg;base64,${base64Image}`;
    } catch (e: any) {
      // Fallback to flash image for higher reliability during quota stress
      const fallback = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: `Cinematic high quality photo: ${prompt}` }] },
        config: {
          imageConfig: { 
            aspectRatio: ratio === '16:9' ? '16:9' : '9:16'
          }
        }
      });
      const part = fallback.candidates?.[0]?.content?.parts.find(p => p.inlineData);
      if (!part?.inlineData?.data) throw new Error("Image failed.");
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  static async generateAudio(text: string, voiceName: string): Promise<Uint8Array> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName },
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (!base64Audio) throw new Error("Audio failed");
      return GeminiService.decode(base64Audio);
    } catch (e: any) {
      console.error("Audio failed:", e);
      throw e;
    }
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { 
  Play, Video, Download, Loader2, RefreshCw, Smartphone, Monitor, ShieldCheck, Zap,
  Sparkles, Layers, Settings2, ArrowRight, CheckCircle2, Wand2,
  Volume2, Type, Image as ImageIcon, Plus, Edit3, Music, ChevronLeft, User, Users, AlertCircle
} from 'lucide-react';
import { GeminiService } from './services/geminiService';

const LANGUAGES = [
  { id: 'Bengali', name: 'Bengali (বাংলা)', label: 'বাংলা' },
  { id: 'Hindi', name: 'Hindi (हिन्दी)', label: 'हिन्दी' },
  { id: 'English', name: 'English', label: 'English' },
];

const GENDERS = [
  { id: 'Male', label: 'পুরুষ (Male)', voice: 'Fenrir' },
  { id: 'Female', label: 'মহিলা (Female)', voice: 'Zephyr' },
];

const RATIOS = [
  { id: '9:16', name: 'Portrait', width: 720, height: 1280, icon: <Smartphone size={16} /> },
  { id: '16:9', name: 'Landscape', width: 1280, height: 720, icon: <Monitor size={16} /> }
];

const App: React.FC = () => {
  const [isLaunched, setIsLaunched] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [scenes, setScenes] = useState<any[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [status, setStatus] = useState('');
  const [exporting, setExporting] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [ratio, setRatio] = useState(RATIOS[0]);
  const [lang, setLang] = useState(LANGUAGES[0]);
  const [gender, setGender] = useState(GENDERS[1]);
  const [isKeySelected, setIsKeySelected] = useState<boolean | null>(null);

  const audioRef = useRef(new Audio());

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        try {
          const hasKey = await window.aistudio.hasSelectedApiKey();
          setIsKeySelected(hasKey);
        } catch (e) {
          setIsKeySelected(false);
        }
      } else {
        setIsKeySelected(true);
      }
    };
    checkKey();
  }, []);

  const pcmToWav = (pcmData: Int16Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + pcmData.length * 2);
    const view = new DataView(buffer);
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i));
    };
    writeString(0, 'RIFF');
    view.setUint32(4, 32 + pcmData.length * 2, true);
    writeString(8, 'WAVE');
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(36, 'data');
    view.setUint32(40, pcmData.length * 2, true);
    for (let i = 0; i < pcmData.length; i++) view.setInt16(44 + i * 2, pcmData[i], true);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const generate = async () => {
    if (!prompt.trim()) {
        setStatus("দয়া করে আপনার বিষয়বস্তু লিখুন!");
        return;
    }
    setLoading(true);
    setStatus('প্রক্রিয়া শুরু হচ্ছে...');
    setScenes([]);
    setCurrentIndex(0);

    try {
      const generatedScript = await GeminiService.generateScript(prompt, lang.name, ratio.id);

      const newScenes: any[] = [];
      for (let i = 0; i < generatedScript.length; i++) {
        setStatus(`সিন ${i + 1}/${generatedScript.length} তৈরি হচ্ছে...`);

        // Generate assets with error catching for quota
        try {
          const imagePromises = generatedScript[i].img_prompts.map((p: string) => GeminiService.generateImage(p, ratio.id));
          const audioPromise = GeminiService.generateAudio(generatedScript[i].text, gender.voice);

          const [images, audioBytes] = await Promise.all([
            Promise.all(imagePromises),
            audioPromise
          ]);

          const wavBlob = pcmToWav(new Int16Array(audioBytes.buffer), 24000);
          const audioUrl = URL.createObjectURL(wavBlob);

          newScenes.push({ 
            images, 
            text: generatedScript[i].text, 
            audio: audioUrl,
            id: Date.now() + i
          });
          setScenes([...newScenes]);
        } catch (sceneErr: any) {
          console.error("Scene generation error:", sceneErr);
          if (sceneErr.message?.includes("quota")) {
            setStatus("কোটা শেষ হয়ে গেছে! কিছুক্ষণ পর আবার চেষ্টা করুন।");
            setLoading(false);
            return;
          }
          throw sceneErr;
        }
      }
      setStatus('ভিডিও এখন প্রস্তুত!');
    } catch (e: any) {
      console.error(e);
      if (e.message?.includes("quota")) {
        setStatus("API কোটা শেষ! দয়া করে কিছুক্ষণ পর চেষ্টা করুন।");
      } else {
        setStatus('ভুল হয়েছে, আবার চেষ্টা করুন।');
      }
    } finally {
      setLoading(false);
    }
  };

  const playPreview = async () => {
    if (isPlaying || scenes.length === 0) return;
    setIsPlaying(true);
    for (let i = 0; i < scenes.length; i++) {
      setCurrentIndex(i);
      audioRef.current.src = scenes[i].audio;
      await audioRef.current.play();

      const imgSwitchInterval = setInterval(() => {
        setCurrentImageIndex(prev => (prev + 1) % 4);
      }, 1000);

      await new Promise(r => audioRef.current.onended = r);
      clearInterval(imgSwitchInterval);
      setCurrentImageIndex(0);
    }
    setIsPlaying(false);
    setCurrentIndex(0);
  };

  const exportVideo = async () => {
    if (scenes.length === 0) return;
    setExporting(true);
    setStatus("হাই-কোয়ালিটি ভিডিও রেন্ডার হচ্ছে...");

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    canvas.width = ratio.width;
    canvas.height = ratio.height;

    const stream = canvas.captureStream(30);
    const mediaRecorder = new MediaRecorder(stream, { 
      mimeType: 'video/webm;codecs=vp9', 
      videoBitsPerSecond: 20000000 
    });

    const chunks: Blob[] = [];
    mediaRecorder.ondataavailable = (e) => {
      if (e.data.size > 0) chunks.push(e.data);
    };

    const exportComplete = new Promise<void>((resolve) => {
      mediaRecorder.onstop = () => {
        const blob = new Blob(chunks, { type: 'video/webm' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Babu_Studio_Full_Video_${Date.now()}.webm`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        resolve();
      };
    });

    mediaRecorder.start();

    // Loop through each scene accurately
    for (const scene of scenes) {
      const loadedImages = await Promise.all(scene.images.map((src: string) => {
        return new Promise<HTMLImageElement>((resolve) => {
          const img = new Image();
          img.crossOrigin = "anonymous";
          img.src = src;
          img.onload = () => resolve(img);
          img.onerror = () => resolve(new Image()); // Fallback to avoid breaking loop
        });
      }));

      // Render 5 seconds per scene (150 frames at 30fps) for a solid duration
      for (let f = 0; f < 150; f++) {
        const currentImg = loadedImages[Math.floor(f / 37.5) % 4]; // Switch roughly every 1.25s

        ctx.fillStyle = '#050505';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        if (currentImg && currentImg.width > 0) {
          const s = Math.max(canvas.width / currentImg.width, canvas.height / currentImg.height);
          const w = currentImg.width * s, h = currentImg.height * s;
          ctx.drawImage(currentImg, (canvas.width - w) / 2, (canvas.height - h) / 2, w, h);
        }

        const fontSize = Math.floor(canvas.width * 0.05);
        ctx.font = `bold ${fontSize}px 'Inter', sans-serif`;
        ctx.textAlign = 'center';

        const words = scene.text.split(' ');
        let lines: string[] = [], line = '';
        for (let word of words) {
          if (ctx.measureText(line + word).width > canvas.width * 0.85) {
            lines.push(line.trim());
            line = word + ' ';
          } else { line += word + ' '; }
        }
        lines.push(line.trim());

        const boxPadding = 40;
        const boxH = lines.length * fontSize * 1.5 + boxPadding;

        ctx.fillStyle = 'rgba(0,0,0,0.85)';
        ctx.beginPath();
        ctx.roundRect(canvas.width * 0.05, canvas.height - boxH - 120, canvas.width * 0.9, boxH, 24);
        ctx.fill();

        ctx.fillStyle = '#facc15';
        lines.forEach((l, idx) => {
          ctx.fillText(l, canvas.width / 2, (canvas.height - boxH - 60) + (idx * fontSize * 1.4));
        });

        // Wait for next frame
        await new Promise(rq => requestAnimationFrame(rq));
      }
    }

    // Give it a small buffer to ensure the last frame is captured
    await new Promise(r => setTimeout(r, 500));
    mediaRecorder.stop();
    await exportComplete;

    setExporting(false);
    setStatus("ভিডিও ডাউনলোড সম্পন্ন হয়েছে!");
  };

  if (!isLaunched) {
    return (
      <div className="min-h-screen bg-[#050505] text-white flex flex-col items-center justify-center relative overflow-hidden font-sans">
        <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-yellow-500/10 rounded-full blur-[160px]" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-600/5 rounded-full blur-[160px]" />

        <div className="max-w-4xl w-full px-6 flex flex-col items-center text-center z-10 animate-in fade-in slide-in-from-bottom-10 duration-1000">
          <div className="inline-flex items-center gap-2 bg-white/5 border border-white/10 px-6 py-2 rounded-full mb-8 backdrop-blur-xl">
            <Sparkles size={14} className="text-yellow-500" />
            <span className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-400">Ultra High Performance AI</span>
          </div>

          <h1 className="text-7xl md:text-9xl font-black tracking-tighter leading-[0.8] uppercase mb-8">
            BABU <span className="text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-yellow-600">STUDIO</span>
          </h1>

          <p className="text-zinc-400 text-lg md:text-2xl max-w-2xl mx-auto font-medium leading-relaxed mb-12">
            প্রতিটি লাইনে ৪টি AI ফটো দিয়ে <span className="text-white">ফুল ভিডিও</span> তৈরি করুন মুহূর্তেই।
          </p>

          <button onClick={() => { setStatus(''); handleLaunch(); }} className="group relative bg-white text-black font-black px-12 py-8 rounded-[2rem] flex items-center gap-4 shadow-2xl hover:-translate-y-2 transition-all active:scale-95">
            <div className="absolute inset-0 bg-yellow-500 translate-x-full group-hover:translate-x-0 transition-transform duration-500" />
            <span className="relative z-10 flex items-center gap-3 text-xl tracking-tight uppercase">স্টুডিও ওপেন করুন</span>
            <ArrowRight size={24} className="relative z-10" />
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#050505] text-white flex flex-col h-screen overflow-hidden selection:bg-yellow-500 selection:text-black">
      <header className="h-16 border-b border-white/5 px-6 flex items-center justify-between bg-zinc-900/10 backdrop-blur-2xl z-50">
        <div className="flex items-center gap-4">
          <button onClick={() => setIsLaunched(false)} className="p-2 hover:bg-white/5 rounded-xl text-zinc-500 transition-colors">
            <ChevronLeft size={20} />
          </button>
          <div className="flex items-center gap-3">
            <div className="bg-yellow-500 p-1.5 rounded-lg text-black">
              <Sparkles size={16} fill="currentColor"/>
            </div>
            <h1 className="text-sm font-black tracking-widest uppercase">Babu Studio Pro</h1>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {scenes.length > 0 && (
            <button onClick={exportVideo} disabled={exporting || loading} className="bg-white text-black px-6 py-2.5 rounded-full text-[10px] font-black flex items-center gap-2 hover:bg-zinc-200 transition-all disabled:opacity-30 shadow-xl">
              {exporting ? <Loader2 className="animate-spin" size={14} /> : <Download size={14} strokeWidth={3} />}
              {exporting ? "SAVING..." : "DOWNLOAD FULL VIDEO"}
            </button>
          )}
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden">
        <aside className="w-80 border-r border-white/5 flex flex-col bg-zinc-900/5 overflow-y-auto custom-scrollbar">
          <div className="p-6 space-y-6">
            <div className="flex items-center justify-between text-zinc-500">
              <span className="text-[10px] font-black uppercase tracking-widest">Scenes</span>
              <span className="text-[10px] font-bold bg-zinc-800 px-2 py-0.5 rounded">{scenes.length}</span>
            </div>

            <div className="space-y-4">
              {scenes.length > 0 ? (
                scenes.map((scene, idx) => (
                  <div key={scene.id} onClick={() => { setCurrentIndex(idx); setCurrentImageIndex(0); }} className={`group p-4 rounded-3xl border transition-all cursor-pointer ${currentIndex === idx ? 'bg-zinc-900 border-white/10 ring-1 ring-yellow-500/20' : 'bg-transparent border-white/5 hover:bg-white/5'}`}>
                    <div className="flex gap-4">
                      <div className="relative w-16 h-16 rounded-2xl overflow-hidden bg-zinc-800 shrink-0 border border-white/5">
                        <img src={scene.images[0]} className="w-full h-full object-cover" alt="thumb" />
                        <div className="absolute inset-0 bg-black/40 flex items-center justify-center text-[10px] font-black">{idx + 1}</div>
                      </div>
                      <div className="flex-1 overflow-hidden">
                        <p className="text-[11px] text-zinc-400 line-clamp-3 leading-relaxed">{scene.text}</p>
                        <div className="mt-2 flex gap-1">
                          {[1,2,3,4].map(n => <div key={n} className="w-1.5 h-1.5 rounded-full bg-yellow-500/40" />)}
