              ) : (
                <div className="py-24 text-center opacity-20 flex flex-col items-center gap-4">
                  <Layers size={40} strokeWidth={1} />
                  <p className="text-[10px] font-black uppercase tracking-widest">Generate Content</p>
                </div>
              )}
            </div>
          </div>
        </aside>

        <main className="flex-1 flex flex-col bg-[radial-gradient(circle_at_center,_#111_0%,_#050505_100%)] overflow-hidden">
          <div className="flex-1 p-8 flex flex-col items-center justify-center relative">
            <div className="relative w-full max-w-4xl bg-[#000] rounded-[3rem] overflow-hidden shadow-2xl group ring-1 ring-white/5 transition-all duration-500" style={{ aspectRatio: ratio.id === '9:16' ? '9/16' : '16/9', maxHeight: '72vh' }}>
              {scenes.length > 0 ? (
                <>
                  <img src={scenes[currentIndex].images[currentImageIndex]} className="w-full h-full object-cover animate-in fade-in duration-700" alt="scene" />
                  <div className="absolute top-6 left-6 flex gap-2">
                    {scenes[currentIndex].images.map((_, i) => (
                      <div key={i} className={`w-10 h-1.5 rounded-full shadow-lg transition-all ${i === currentImageIndex ? 'bg-yellow-500 w-16' : 'bg-white/30'}`} />
                    ))}
                  </div>
                  <div className="absolute inset-x-0 bottom-0 p-12 bg-gradient-to-t from-black via-black/90 to-transparent">
                    <p className="text-center font-bold text-2xl md:text-3xl lg:text-4xl text-white drop-shadow-2xl leading-tight">{scenes[currentIndex].text}</p>
                  </div>
                  {!isPlaying && (
                    <button onClick={playPreview} className="absolute inset-0 flex items-center justify-center bg-black/20 group-hover:bg-black/10 transition-all backdrop-blur-[1px]">
                      <div className="bg-white text-black p-10 rounded-full shadow-2xl scale-100 hover:scale-110 active:scale-90 transition-all">
                        <Play fill="currentColor" size={48} />
                      </div>
                    </button>
                  )}
                </>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-zinc-800">
                  <Video size={100} strokeWidth={0.5} className="opacity-10" />
                  <p className="text-[12px] font-black uppercase tracking-[0.6em] mt-6 opacity-20">Creative Canvas</p>
                </div>
              )}

              {loading && (
                <div className="absolute inset-0 bg-black/95 backdrop-blur-3xl flex flex-col items-center justify-center gap-10 z-50">
                  <div className="relative">
                    <div className="w-24 h-24 rounded-full border-t-2 border-yellow-500 animate-spin" />
                    <div className="absolute inset-0 flex items-center justify-center">
                      <Sparkles className="text-yellow-500 animate-pulse" size={32} />
                    </div>
                  </div>
                  <div className="text-center px-12">
                    <p className="text-[10px] text-zinc-500 font-black uppercase tracking-[0.5em] mb-3 animate-pulse">Building Your Masterpiece</p>
                    <p className="text-xl font-bold text-white max-w-md mx-auto">{status}</p>
                  </div>
                </div>
              )}
            </div>
          </div>

          <div className="h-72 border-t border-white/5 bg-zinc-900/40 backdrop-blur-3xl p-8 flex gap-10 overflow-x-auto custom-scrollbar">
             <div className="w-96 min-w-[320px] space-y-4">
                <div className="flex items-center gap-2 text-zinc-500">
                  <Edit3 size={14} />
                  <span className="text-[10px] font-black uppercase tracking-widest">Script Generator</span>
                </div>
                <textarea className="w-full bg-zinc-900/50 rounded-2xl p-6 text-sm border border-white/5 focus:border-yellow-500/40 outline-none resize-none placeholder:text-zinc-700 text-zinc-200 h-36 transition-all font-medium custom-scrollbar" placeholder="আপনার ভিডিও আইডিয়া লিখুন..." value={prompt} onChange={(e) => setPrompt(e.target.value)} />
             </div>

             <div className="flex-1 flex gap-10 min-w-[600px]">
                <div className="space-y-4 flex-1">
                  <div className="flex items-center gap-2 text-zinc-500">
                    <Settings2 size={14} />
                    <span className="text-[10px] font-black uppercase tracking-widest">Configuration</span>
                  </div>
                  <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-4">
                      <div className="flex gap-2 bg-zinc-900/60 p-2 rounded-2xl border border-white/5 h-14">
                        {RATIOS.map(r => (
                          <button key={r.id} onClick={() => setRatio(r)} className={`flex-1 flex items-center justify-center gap-2 rounded-xl transition-all ${ratio.id === r.id ? 'bg-white text-black shadow-lg font-black' : 'text-zinc-500 hover:text-white'}`}>
                            {r.icon}
                            <span className="text-[10px] uppercase">{r.name}</span>
                          </button>
                        ))}
                      </div>
                      <select className="w-full bg-zinc-900/60 p-4 rounded-2xl border border-white/5 text-[11px] font-black uppercase tracking-widest outline-none cursor-pointer text-zinc-400 hover:bg-zinc-800 transition-colors h-14 px-6 appearance-none text-center" value={lang.id} onChange={(e) => setLang(LANGUAGES.find(l => l.id === e.target.value)!)}>
                        {LANGUAGES.map(l => <option key={l.id} value={l.id}>{l.label}</option>)}
                      </select>
                    </div>
                    <div className="space-y-3">
                      <div className="text-[9px] font-black uppercase tracking-widest text-zinc-600 mb-1 flex items-center gap-2">Narration Character</div>
                      <div className="grid grid-cols-2 gap-3 h-14">
                        {GENDERS.map(g => (
                          <button key={g.id} onClick={() => setGender(g)} className={`flex items-center justify-center gap-2 rounded-2xl border transition-all text-[10px] font-black uppercase ${gender.id === g.id ? 'bg-zinc-100 text-black border-white shadow-xl' : 'bg-zinc-900/40 border-white/5 text-zinc-500'}`}>
                            <User size={14} /> {g.id}
                          </button>
                        ))}
                      </div>
                      <div className="flex items-center gap-2 bg-zinc-900/40 p-3 rounded-xl border border-white/5 opacity-40">
                        <Volume2 size={12} className="text-zinc-400" />
                        <span className="text-[9px] font-black uppercase tracking-widest text-zinc-400">Multi-Photo Mode Active</span>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="w-64 flex flex-col justify-end">
                   <button onClick={generate} disabled={loading} className="w-full h-32 bg-yellow-500 text-black font-black rounded-[2.5rem] flex flex-col items-center justify-center gap-2 hover:bg-yellow-400 transition-all disabled:opacity-50 shadow-2xl shadow-yellow-500/10 group active:scale-95">
                    {loading ? <Loader2 className="animate-spin" size={32}/> : <Zap size={32} fill="currentColor" className="group-hover:scale-110 transition-transform"/>}
                    <span className="text-lg">তৈরি করুন</span>
                  </button>
                </div>
             </div>
          </div>
        </main>
      </div>

      {status && !loading && (
        <div className={`fixed bottom-6 right-6 border px-8 py-4 rounded-[2rem] shadow-2xl animate-in slide-in-from-right-10 flex items-center gap-4 z-[100] backdrop-blur-3xl ${status.includes("কোটা") ? 'bg-red-900/20 border-red-500/50' : 'bg-zinc-900 border-white/10'}`}>
          <div className={`${status.includes("কোটা") ? 'bg-red-500/10' : 'bg-yellow-500/10'} p-2 rounded-full`}>
            {status.includes("কোটা") ? <AlertCircle size={20} className="text-red-500" /> : <CheckCircle2 size={20} className="text-yellow-500" />}
          </div>
          <span className="text-[11px] font-black uppercase tracking-widest text-zinc-200">{status}</span>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { 
  Play, Video, Download, Loader2, RefreshCw, Smartphone, Monitor, ShieldCheck, Zap,
  Sparkles, Layers, Settings2, ArrowRight, CheckCircle2, Wand2,
  Volume2, Type, Image as ImageIcon, Plus, Edit3, Music, ChevronLeft, User, Users, AlertCircle
} from 'lucide-react';
import { GeminiService } from './services/geminiService';

const LANGUAGES = [
  { id: 'Bengali', name: 'Bengali (বাংলা)', label: 'বাংলা' },
  { id: 'Hindi', name: 'Hindi (हिन्दी)', label: 'हिन्दी' },
  { id: 'English', name: 'English', label: 'English' },
];

const GENDERS = [
  { id: 'Male', label: 'পুরুষ (Male)', voice: 'Fenrir' },
  { id: 'Female', label: 'মহিলা (Female)', voice: 'Zephyr' },
];

const RATIOS = [
  { id: '9:16', name: 'Portrait', width: 720, height: 1280, icon: <Smartphone size={16} /> },
  { id: '16:9', name: 'Landscape', width: 1280, height: 720, icon: <Monitor size={16} /> }
];

const App: React.FC = () => {
  const [isLaunched, setIsLaunched] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [scenes, setScenes] = useState<any[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [status, setStatus] = useState('');
  const [exporting, setExporting] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [ratio, setRatio] = useState(RATIOS[0]);
  const [lang, setLang] = useState(LANGUAGES[0]);
  const [gender, setGender] = useState(GENDERS[1]);
  const [isKeySelected, setIsKeySelected] = useState<boolean | null>(null);

  const audioRef = useRef(new Audio());

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        try {
          const hasKey = await window.aistudio.hasSelectedApiKey();
          setIsKeySelected(hasKey);
        } catch (e) {
          setIsKeySelected(false);
        }
      } else {
        setIsKeySelected(true);
      }
    };
    checkKey();
  }, []);

  // Fix: Added missing handleLaunch function to handle studio entry and API key selection requirements
  const handleLaunch = async () => {
    if (window.aistudio?.hasSelectedApiKey) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        try {
          await window.aistudio.openSelectKey();
          // To mitigate race condition, proceed assuming selection was successful
        } catch (e) {
          console.error("Failed to open key selector", e);
        }
      }
    }
    setIsLaunched(true);
  };

  const pcmToWav = (pcmData: Int16Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + pcmData.length * 2);
    const view = new DataView(buffer);
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i));
    };
    writeString(0, 'RIFF');
    view.setUint32(4, 32 + pcmData.length * 2, true);
    writeString(8, 'WAVE');
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(36, 'data');
    view.setUint32(40, pcmData.length * 2, true);
    for (let i = 0; i < pcmData.length; i++) view.setInt16(44 + i * 2, pcmData[i], true);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const generate = async () => {
    if (!prompt.trim()) {
        setStatus("দয়া করে আপনার বিষয়বস্তু লিখুন!");
        return;
    }
    setLoading(true);
    setStatus('প্রক্রিয়া শুরু হচ্ছে...');
    setScenes([]);
    setCurrentIndex(0);

    try {
      const generatedScript = await GeminiService.generateScript(prompt, lang.name, ratio.id);

      const newScenes: any[] = [];
      for (let i = 0; i < generatedScript.length; i++) {
        setStatus(`সিন ${i + 1}/${generatedScript.length} তৈরি হচ্ছে...`);

        // Generate assets with error catching for quota
        try {
          const imagePromises = generatedScript[i].img_prompts.map((p: string) => GeminiService.generateImage(p, ratio.id));
          const audioPromise = GeminiService.generateAudio(generatedScript[i].text, gender.voice);

          const [images, audioBytes] = await Promise.all([
            Promise.all(imagePromises),
            audioPromise
          ]);

          const wavBlob = pcmToWav(new Int16Array(audioBytes.buffer), 24000);
          const audioUrl = URL.createObjectURL(wavBlob);

          newScenes.push({ 
            images, 
            text: generatedScript[i].text, 
            audio: audioUrl,
            id: Date.now() + i
          });
          setScenes([...newScenes]);
        } catch (sceneErr: any) {
          console.error("Scene generation error:", sceneErr);
          // Fix: Reset key selection if request fails with "Requested entity was not found"
          if (sceneErr.message?.includes("Requested entity was not found") && window.aistudio?.openSelectKey) {
             await window.aistudio.openSelectKey();
          }
          if (sceneErr.message?.includes("quota")) {
            setStatus("কোটা শেষ হয়ে গেছে! কিছুক্ষণ পর আবার চেষ্টা করুন।");
            setLoading(false);
            return;
          }
          throw sceneErr;
        }
      }
      setStatus('ভিডিও এখন প্রস্তুত!');
    } catch (e: any) {
      console.error(e);
      if (e.message?.includes("quota")) {
        setStatus("API কোটা শেষ! দয়া করে কিছুক্ষণ পর চেষ্টা করুন।");
      } else {
        setStatus('ভুল হয়েছে, আবার চেষ্টা করুন।');
      }
    } finally {
      setLoading(false);
    }
  };

  const playPreview = async () => {
    if (isPlaying || scenes.length === 0) return;
    setIsPlaying(true);
    for (let i = 0; i < scenes.length; i++) {
      setCurrentIndex(i);
      audioRef.current.src = scenes[i].audio;
      await audioRef.current.play();

      const imgSwitchInterval = setInterval(() => {
        setCurrentImageIndex(prev => (prev + 1) % 4);
      }, 1000);

      await new Promise(r => audioRef.current.onended = r);
      clearInterval(imgSwitchInterval);
      setCurrentImageIndex(0);
    }
    setIsPlaying(false);
    setCurrentIndex(0);
  };

  const exportVideo = async () => {
    if (scenes.length === 0) return;
    setExporting(true);
    setStatus("হাই-কোয়ালিটি ভিডিও রেন্ডার হচ্ছে...");

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;
    canvas.width = ratio.width;
    canvas.height = ratio.height;

    const stream = canvas.captureStream(30);
    const mediaRecorder = new MediaRecorder(stream, { 
      mimeType: 'video/webm;codecs=vp9', 
      videoBitsPerSecond: 20000000 
    });

    const chunks: Blob[] = [];
    mediaRecorder.ondataavailable = (e) => {
      if (e.data.size > 0) chunks.push(e.data);
    };

    const exportComplete = new Promise<void>((resolve) => {
      mediaRecorder.onstop = () => {
        const blob = new Blob(chunks, { type: 'video/webm' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Babu_Studio_Full_Video_${Date.now()}.webm`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        resolve();
      };
    });

    mediaRecorder.start();

    // Loop through each scene accurately
    for (const scene of scenes) {
      const loadedImages = await Promise.all(scene.images.map((src: string) => {
        return new Promise<HTMLImageElement>((resolve) => {
          const img = new Image();
          img.crossOrigin = "anonymous";
          img.src = src;
          img.onload = () => resolve(img);
          img.onerror = () => resolve(new Image()); // Fallback to avoid breaking loop
        });
      }));

      // Render 5 seconds per scene (150 frames at 30fps) for a solid duration
      for (let f = 0; f < 150; f++) {
        const currentImg = loadedImages[Math.floor(f / 37.5) % 4]; // Switch roughly every 1.25s

        ctx.fillStyle = '#050505';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        if (currentImg && currentImg.width > 0) {
          const s = Math.max(canvas.width / currentImg.width, canvas.height / currentImg.height);
          const w = currentImg.width * s, h = currentImg.height * s;
          ctx.drawImage(currentImg, (canvas.width - w) / 2, (canvas.height - h) / 2, w, h);
        }

        const fontSize = Math.floor(canvas.width * 0.05);
        ctx.font = `bold ${fontSize}px 'Inter', sans-serif`;
        ctx.textAlign = 'center';

        const words = scene.text.split(' ');
        let lines: string[] = [], line = '';
        for (let word of words) {
          if (ctx.measureText(line + word).width > canvas.width * 0.85) {
            lines.push(line.trim());
            line = word + ' ';
          } else { line += word + ' '; }
        }
        lines.push(line.trim());

        const boxPadding = 40;
        const boxH = lines.length * fontSize * 1.5 + boxPadding;

        ctx.fillStyle = 'rgba(0,0,0,0.85)';
        ctx.beginPath();
        ctx.roundRect(canvas.width * 0.05, canvas.height - boxH - 120, canvas.width * 0.9, boxH, 24);
        ctx.fill();

        ctx.fillStyle = '#facc15';
        lines.forEach((l, idx) => {
          ctx.fillText(l, canvas.width / 2, (canvas.height - boxH - 60) + (idx * fontSize * 1.4));
        });

        // Wait for next frame
        await new Promise(rq => requestAnimationFrame(rq));
      }
    }

    // Give it a small buffer to ensure the last frame is captured
    await new Promise(r => setTimeout(r, 500));
    mediaRecorder.stop();
    await exportComplete;

    setExporting(false);
    setStatus("ভিডিও ডাউনলোড সম্পন্ন হয়েছে!");
  };

  if (!isLaunched) {
