          </p>

          <button onClick={() => { setStatus(''); handleLaunch(); }} className="group relative bg-white text-black font-black px-12 py-8 rounded-[2rem] flex items-center gap-4 shadow-2xl hover:-translate-y-2 transition-all active:scale-95">
            <div className="absolute inset-0 bg-yellow-500 translate-x-full group-hover:translate-x-0 transition-transform duration-500" />
