            </div>

            <div className="space-y-4">
              {scenes.length > 0 ? (
                scenes.map((scene, idx) => (
                  <div key={scene.id} onClick={() => { setCurrentIndex(idx); setCurrentImageIndex(0); }} className={`group p-4 rounded-3xl border transition-all cursor-pointer ${currentIndex === idx ? 'bg-zinc-900 border-white/10 ring-1 ring-yellow-500/20' : 'bg-transparent border-white/5 hover:bg-white/5'}`}>
