export default App;

import { GoogleGenAI, Modality } from "@google/genai";

export interface Scene {
  images: string[];
  text: string;
  audio: Uint8Array;
}

export class GeminiService {
  private static decode(base64: string) {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  }

  static async generateScript(prompt: string, lang: string, ratio: string): Promise<any[]> {
    // Initializing right before use to ensure latest API key is picked up
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const systemInstruction = `You are an elite video scriptwriter. 
    Create a cinematic 3-scene video script in ${lang} based on: "${prompt}".

    RULES:
    1. "text" field: MUST be in ${lang}. Max 12 words.
    2. "img_prompts" field: Provide exactly 4 high-quality English prompts for images.
    3. Optimized for ${ratio} aspect ratio.

    Return ONLY JSON: { "scenes": [{ "img_prompts": ["p1", "p2", "p3", "p4"], "text": "text" }] }`;

    try {
      // Using gemini-3-flash-preview for high performance script generation
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          systemInstruction,
          responseMimeType: "application/json",
          temperature: 0.7
        }
      });

      // Using .text property directly as per guidelines
      const textOutput = response.text || '{}';
      const data = JSON.parse(textOutput);
      return data.scenes || [];
    } catch (e: any) {
      console.error("Script generation failed:", e);
      throw e;
    }
  }

  static async generateImage(prompt: string, ratio: string): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      // High-quality imagen attempt
      const response = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: `Professional cinematic photography, 8k, photorealistic: ${prompt}`,
        config: {
          numberOfImages: 1,
          outputMimeType: 'image/jpeg',
          aspectRatio: ratio === '16:9' ? '16:9' : '9:16',
        },
      });

      const base64Image = response.generatedImages[0].image.imageBytes;
      return `data:image/jpeg;base64,${base64Image}`;
    } catch (e: any) {
      console.warn("Imagen failed, falling back to gemini-2.5-flash-image", e);
      // Fallback to gemini-2.5-flash-image which is the default recommended model
      const fallback = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: `Cinematic high quality photo: ${prompt}` }] },
        config: {
          imageConfig: { 
            aspectRatio: ratio === '16:9' ? '16:9' : '9:16'
          }
        }
      });
      // Iterate through candidates and parts to find the image part
      const part = fallback.candidates?.[0]?.content?.parts.find(p => p.inlineData);
      if (!part?.inlineData?.data) throw new Error("Image generation failed.");
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  static async generateAudio(text: string, voiceName: string): Promise<Uint8Array> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      // Using gemini-2.5-flash-preview-tts for high-quality speech generation
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName },
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (!base64Audio) throw new Error("Audio generation failed");
      return GeminiService.decode(base64Audio);
    } catch (e: any) {
      console.error("Audio generation failed:", e);
      throw e;
    }
  }
}
